const STREAK_SVG_FUEL = '<img src="assets/images/fuelcell-icon-new.png" style="width:22px;height:22px;object-fit:contain;">';
const STREAK_SVG_ROCKET = '<img src="assets/images/rocket-icon.png" style="width:22px;height:22px;object-fit:contain;">';

const STREAK_REWARDS = [
  { day: 1, coins: 25,  fuel: 0, heads: 0, svg: 'coin',    color: '#ffcc00' },
  { day: 2, coins: 50,  fuel: 0, heads: 0, svg: 'coin',    color: '#ffcc00' },
  { day: 3, coins: 0,   fuel: 3, heads: 0, svg: 'fuel',    color: '#4488ff' },
  { day: 4, coins: 75,  fuel: 2, heads: 0, svg: 'both',    color: '#ffcc00' },
  { day: 5, coins: 100, fuel: 0, heads: 0, svg: 'coin',    color: '#ffcc00' },
  { day: 6, coins: 0,   fuel: 5, heads: 0, svg: 'fuel',    color: '#4488ff' },
  { day: 7, coins: 150, fuel: 5, heads: 1, svg: 'rocket',  color: '#ff6600' },
];

const STREAK_KEY_DAY = 'jh_streak_day';
const STREAK_KEY_LAST = 'jh_streak_last_claim';

function getTodayStr() {
  const d = new Date();
  return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
}
function getYesterdayStr() {
  const d = new Date();
  d.setDate(d.getDate() - 1);
  return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
}

function loadStreakState() {
  const lastClaim = localStorage.getItem(STREAK_KEY_LAST);
  let day = parseInt(localStorage.getItem(STREAK_KEY_DAY)) || 1;
  const today = getTodayStr();
  const yesterday = getYesterdayStr();

  if (!lastClaim) {
    return { day: 1, claimed: false };
  }
  if (lastClaim === today) {
    return { day: day, claimed: true };
  }
  if (lastClaim === yesterday) {
    day = day >= 7 ? 1 : day + 1;
    return { day: day, claimed: false };
  }
  // Missed a day — reset
  return { day: 1, claimed: false };
}

function renderStreakCircles() {
  const container = document.getElementById('streak-circles');
  if (!container) return;
  container.innerHTML = '';
  const ss = loadStreakState();

  for (let i = 0; i < 7; i++) {
    const r = STREAK_REWARDS[i];
    const dayNum = i + 1;
    const el = document.createElement('div');
    el.className = 'streak-day';
    el.dataset.day = dayNum;

    el.innerHTML = '<span class="streak-num">' + dayNum + '</span>';

    // State
    if (dayNum < ss.day || (dayNum === ss.day && ss.claimed)) {
      el.classList.add('claimed');
    } else if (dayNum === ss.day && !ss.claimed) {
      el.classList.add('today');
      _tapBind(el, () => claimStreakReward(el, ss.day));
      el.addEventListener('touchstart', (e) => { e.preventDefault(); claimStreakReward(el, ss.day); }, { passive: false });
    } else {
      el.classList.add('future');
    }

    container.appendChild(el);
  }
}

function claimStreakReward(el, dayNum) {
  if (el.classList.contains('claimed')) return;
  playTitleTap();
  el.classList.remove('today');
  el.classList.add('burst');

  const r = STREAK_REWARDS[dayNum - 1];

  // Save streak state FIRST so it persists no matter what
  localStorage.setItem(STREAK_KEY_DAY, '' + dayNum);
  localStorage.setItem(STREAK_KEY_LAST, getTodayStr());

  // Apply rewards
  if (r.coins > 0) {
    const cur = loadCoinWallet();
    saveCoinWallet(cur + r.coins);
    document.getElementById('title-coin-count').textContent = (cur + r.coins).toLocaleString();
  }
  if (r.fuel > 0) {
    const cur = loadFuelCells();
    saveFuelCells(cur + r.fuel);
    document.getElementById('title-fuelcell-count').textContent = (cur + r.fuel).toLocaleString();
  }
  if (r.heads > 0) {
    const cur = parseInt(localStorage.getItem('jh_headstarts') || '0');
    localStorage.setItem('jh_headstarts', '' + (cur + r.heads));
  }

  // Mark claimed visually
  setTimeout(() => {
    el.classList.remove('burst');
    el.classList.add('claimed');
  }, 400);

  // Show streak popup — dynamic element appended to body (same pattern as handling-popup)
  const elRect = el.getBoundingClientRect();
  const popup = document.createElement('div');
  popup.className = 'streak-claim-popup';
  popup.textContent = '\uD83D\uDD25 ' + dayNum + ' Day Streak!';
  popup.style.left = (elRect.left + elRect.width / 2) + 'px';
  popup.style.top = (elRect.top - 6) + 'px';
  document.body.appendChild(popup);
  requestAnimationFrame(() => popup.classList.add('show'));
  setTimeout(() => { popup.classList.add('fade'); setTimeout(() => popup.remove(), 600); }, 1800);

  // Bezier fly particles — coins fly to coin HUD, fuel flies to fuel HUD
  const ox = elRect.left + elRect.width / 2;
  const oy = elRect.top + elRect.height / 2;
  function _streakFly(count, color, glow, targetEl) {
    const rect = targetEl.getBoundingClientRect();
    const tx = rect.left + rect.width / 2;
    const ty = rect.top + rect.height / 2;
    for (let i = 0; i < count; i++) {
      const dot = document.createElement('div');
      const size = 6 + Math.random() * 7;
      const startX = ox + (Math.random() - 0.5) * 40;
      const startY = oy + (Math.random() - 0.5) * 40;
      const delay = i * 25;
      const dur = 500 + Math.random() * 250;
      const midX = (startX + tx) / 2 + (Math.random() - 0.5) * 100;
      const midY = Math.min(startY, ty) - 30 - Math.random() * 70;
      dot.style.cssText = `position:fixed;left:0;top:0;width:${size}px;height:${size}px;background:${color};border-radius:50%;box-shadow:0 0 ${size+3}px ${glow};z-index:9999;pointer-events:none;will-change:transform,opacity;`;
      document.body.appendChild(dot);
      const start = performance.now() + delay;
      (function tick(now) {
        const elapsed = now - start;
        if (elapsed < 0) { requestAnimationFrame(tick); return; }
        const t = Math.min(1, elapsed / dur);
        const ease = t < 0.5 ? 2*t*t : -1+(4-2*t)*t;
        const bx = (1-ease)*(1-ease)*startX + 2*(1-ease)*ease*midX + ease*ease*tx;
        const by = (1-ease)*(1-ease)*startY + 2*(1-ease)*ease*midY + ease*ease*ty;
        const s = 1 - ease * 0.7;
        const op = t > 0.7 ? 1 - (t - 0.7) / 0.3 : 1;
        dot.style.transform = `translate(${bx}px,${by}px) scale(${s})`;
        dot.style.opacity = op;
        if (t < 1) requestAnimationFrame(tick);
        else dot.remove();
      })(performance.now());
    }
  }
  const coinHud = document.getElementById('title-coin-count');
  const fuelHud = document.getElementById('title-fuelcell-count');
  if (r.coins > 0 && coinHud) _streakFly(Math.min(30, Math.max(12, (r.coins / 3) | 0)), '#ffd700', '#fa0', coinHud);
  if (r.fuel > 0 && fuelHud)  _streakFly(Math.min(25, Math.max(10, r.fuel * 4)), '#4cf', '#0af', fuelHud);

  // Play SFX
  playRewardSFX();

  // Hide badge
  const badge = document.getElementById('streak-badge');
  if (badge) badge.classList.add('hidden');

  // Auto-dismiss overlay
  setTimeout(() => {
    document.getElementById('streak-overlay').classList.add('hidden');
  }, 1800);
}

function openStreak() {
  initAudio();
  playTitleTap();
  renderStreakCircles();
  document.getElementById('streak-overlay').classList.remove('hidden');
  // Hide badge when panel opens
  const badge = document.getElementById('streak-badge');
  if (badge) badge.classList.add('hidden');
}
window.openStreak = openStreak;

// Close streak overlay — X button or tap outside panel
function closeStreak() {
  playTitleTap();
  document.getElementById('streak-overlay').classList.add('hidden');
}
_tapBind(document.getElementById('streak-close-btn'), closeStreak);
document.getElementById('streak-overlay').addEventListener('click', function(e) {
  if (e.target === this) closeStreak();
});

// Update streak badge + day counter on title screen load
function updateStreakBadge() {
  const ss = loadStreakState();
  const badge = document.getElementById('streak-badge');
  if (badge) {
    if (!ss.claimed) badge.classList.remove('hidden');
    else badge.classList.add('hidden');
  }
  // Update day counter label (e.g. "3/7")
  const dayLabel = document.getElementById('streak-day-label');
  if (dayLabel) dayLabel.textContent = ss.day + '/7';
}

// ═══════════════════════════════════════════════════
// ─────────────────────────────────────────────────────────────────────────
// SHIP GARAGE / SHOWROOM (Path A — reuses live title scene)
//
// Layers a sci-fi UI panel over the existing title canvas. The title scene
// already has a cloned ship + studio lighting + spinGroup for rotation, so
// the "showroom" is literally the title preview seen through a docked panel.
//
// Public API (exposed as window.Showroom):
//   open(tab)    — show panel, populate dropdowns, reframe camera
//   close()      — hide panel, restore camera
//   refresh()    — re-read storage and rebuild dropdowns (e.g. after admin unlock)
//
// Coupling:
//   Reads:   SHIP_SKINS, _THRUSTER_PRESETS, _THRUSTER_COLOR_PALETTE,
//            loadSkinData, loadThrusterData, isSkinUnlocked, _skinAdminMode,
//            MISSION_LADDER, titleCamera, titleScene
//   Writes:  saveSkinData (via navigateToSkin), saveThrusterData
//   Calls:   navigateToSkin(idx), _applyEquippedThruster(),
//            _applyThrusterPresetByKey, _applyThrusterColorByKey, playTitleTap
// ─────────────────────────────────────────────────────────────────────────

(function _installShowroom() {
  'use strict';

  // ── State ────────────────────────────────────────────────────────────
  let _open = false;
  let _activeTab = 'thrusters';
  let _wired = false;
  let _resizeBound = false;
  // Saved canvas placement so we can restore on close.
  let _canvasSaved = null; // { parent, nextSibling, w, h, transform, dpr, camAspect, rendererW, rendererH }

  // ── Showroom-only thruster preview (independent of gameplay systems) ──
  // Lifted from updateThrusters() in 20-main-early.js. Same particle spawn
  // rules + bloom sprite, but with fixed 'speed' and the title ship's nozzle
  // world position. Reads _THRUSTER_PRESETS knobs (window.*) so changing the
  // SHAPE dropdown re-tunes immediately. Reads _THRUSTER_COLOR_PALETTE for
  // COLOR. Lives entirely in titleScene; gameplay scene is untouched.
  const SR_PARTICLE_COUNT = 80; // per pod (gameplay uses 160; this is a stationary preview)
  let _thr = null; // { points[2], geo[2], pos[2], col[2], sz[2], vel[2][], age[2], life[2], bloom[2], color }
  // Showroom-side base values (mirrors of gameplay defaults at the call site).
  // Used so showroom particles look right even before any preset is applied.
  const SR_DEFAULTS = {
    posPinFrac: 0.12, lifeMin: 0.18, lifeJit: 0.22, lifeBase: 0.6, lifeSpd: 0.9, spawnJit: 0.03,
    coreEnd: 0.10, coreR: 1.00, coreGB: 0.85, midEnd: 0.65, midBoost: 0.30,
    sizeBase: 0.22, sizeSpeed: 0.10, bumpMult: 1.60, bumpEnd: 0.10, sizeJitter: 0.06,
    bloomScale: 0.4, bloomOpacity: 0.18, bloomWhiteMix: 0.0, bloomPulse: 0.15,
    partOpacity: 1.0,
  };
  // Fixed per-frame inputs for the preview (no real ship physics):
  // - speedScale 1.0 (cruise speed, normal preset look)
  // - thrusterPower 1.0 (full power)
  // - shipVelX 0 (no lateral motion → no trail bend)
  const SR_SPEED_SCALE = 1.0;
  const SR_TP = 1.0;

  // ── Drag-tuner state (persists to localStorage) ──────────────────────
  // anchors are children of _titleShipModel — their localPosition IS the
  // tuned offset. Drag updates their localPosition; wheel updates scale.
  // 'flip' inverts the exhaust direction (Z velocity sign).
  // Default-Runner bucket keeps the v7 key so your existing tuned values
  // are preserved. Alt-GLB ships get their own bucket: SR_TUNER_KEY +
  // '__' + glbFile (e.g. 'jh_showroom_tuner_v7__spaceship_01.glb').
  const SR_TUNER_KEY = 'jh_showroom_tuner_v7';
  // Z is relative to auto-detected hull back; 0 = visible hull back.
  // pitch/yaw are exhaust direction angles in degrees (0,0 = straight back along -Z).
  // 'sel' picks which group is being dragged: L|R = main, mL|mR = mini.
  const SR_TUNER_DEFAULT = {
    L:  { x: -1.665, y:  0.010, z: 0.0, scale: 2.854, pitch: 0, yaw: 0 },
    R:  { x:  1.665, y:  0.010, z: 0.0, scale: 2.854, pitch: 0, yaw: 0 },
    mL: { x: -0.852, y:  0.032, z: 0.0, scale: 1.5,   pitch: 0, yaw: 0 },
    mR: { x:  0.852, y:  0.032, z: 0.0, scale: 1.5,   pitch: 0, yaw: 0 },
    mirror: true,
    flip: false,
    rotMode: false, // when true, mouse drag rotates the exhaust angle instead of moving position
    selected: 'L',  // 'L' | 'R' | 'mL' | 'mR'
    // Showroom-local fx overrides (do NOT leak to gameplay).
    fx: {
      bloomScale: 0.40,    // 0..2
      bloomOpacity: 0.18,  // 0..1
      partSize: 1.00,      // 0..3 multiplier on point size
      partOpacity: 1.00,   // 0..1
      lifeBase: 0.10,      // 0.1..2 trail length base
      lifeJit: 0.22,       // 0..1 trail length jitter
      miniSize: 0.55,      // 0.1..2 mini-thruster size mult
      miniBloom: 0.50,     // 0..2 mini-thruster bloom mult
    },
    panelOpen: true,
  };
  let _tuner = null;
  // Tracks which ship's bucket _tuner was loaded from — prevents writing
  // MK Runner pod values into the default Runner bucket and vice versa.
  let _tunerLoadedKey = SR_TUNER_KEY;

  // Resolve the storage key for the currently-displayed ship.
  // INTENTIONALLY a single shared key across all ships — thruster positions
  // are the same for every skin. Per-ship buckets caused stale values to
  // load on swap (one bucket would drift behind the other), making the
  // anchors render in the wrong spot until RST overwrote them. If per-ship
  // tuning is ever needed, gate it behind an explicit user-driven toggle
  // rather than re-introducing implicit per-GLB buckets.
  function _currentTunerKey() {
    return SR_TUNER_KEY;
  }

  function _loadTunerFromKey(key) {
    try {
      const raw = localStorage.getItem(key);
      if (raw) {
        const parsed = JSON.parse(raw);
        return Object.assign({}, SR_TUNER_DEFAULT, parsed, {
          L:  Object.assign({}, SR_TUNER_DEFAULT.L,  parsed.L  || {}),
          R:  Object.assign({}, SR_TUNER_DEFAULT.R,  parsed.R  || {}),
          mL: Object.assign({}, SR_TUNER_DEFAULT.mL, parsed.mL || {}),
          mR: Object.assign({}, SR_TUNER_DEFAULT.mR, parsed.mR || {}),
          fx: Object.assign({}, SR_TUNER_DEFAULT.fx, parsed.fx || {}),
        });
      }
    } catch(_){}
    return JSON.parse(JSON.stringify(SR_TUNER_DEFAULT));
  }

  function _loadTuner() {
    const key = _currentTunerKey();
    _tunerLoadedKey = key;
    return _loadTunerFromKey(key);
  }

  function _saveTuner() {
    if (!_tuner) return;
    try { localStorage.setItem(_tunerLoadedKey, JSON.stringify(_tuner)); } catch(_){}
  }

  // Called from resetThrusterAnchors when the title ship swaps. Persist the
  // outgoing ship's edits, then load the incoming ship's saved values.
  function _swapTunerForCurrentShip() {
    if (_tuner) {
      try { localStorage.setItem(_tunerLoadedKey, JSON.stringify(_tuner)); } catch(_){}
    }
    const key = _currentTunerKey();
    _tunerLoadedKey = key;
    _tuner = _loadTunerFromKey(key);
  }

  // ── Mission-ladder unlock requirement cache (M3, M7, ...) ────────────
  let _unlockReqCache = null;
  function _getUnlockReqs() {
    if (_unlockReqCache) return _unlockReqCache;
    const presets = {}, colors = {}, skins = {};
    let missionCount = 0;
    if (typeof MISSION_LADDER !== 'undefined' && Array.isArray(MISSION_LADDER)) {
      for (let i = 0; i < MISSION_LADDER.length; i++) {
        const r = MISSION_LADDER[i];
        if (r.type === 'mission') { missionCount++; continue; }
        if (r.type !== 'reward' || !r.reward) continue;
        if (r.reward.kind === 'thruster' && r.reward.presetKey) {
          presets[r.reward.presetKey] = missionCount;
        } else if (r.reward.kind === 'thrustercolor' && r.reward.colorKey) {
          colors[r.reward.colorKey] = missionCount;
        } else if (r.reward.kind === 'skin' && typeof r.reward.skinIdx === 'number') {
          skins[r.reward.skinIdx] = missionCount;
        }
      }
    }
    _unlockReqCache = { presets, colors, skins };
    return _unlockReqCache;
  }

  // ── Helpers ──────────────────────────────────────────────────────────
  function _adminAll() {
    return (typeof _skinAdminMode !== 'undefined') && _skinAdminMode;
  }

  function _isPresetUnlocked(key) {
    if (key === 'baseline' || _adminAll()) return true;
    try {
      const td = loadThrusterData();
      return td.unlockedPresets.includes(key);
    } catch(_) { return false; }
  }
  function _isColorUnlocked(key) {
    if (key === 'default' || _adminAll()) return true;
    try {
      const td = loadThrusterData();
      return td.unlockedColors.includes(key);
    } catch(_) { return false; }
  }
  function _isSkinUnlockedSafe(idx) {
    if (idx === 0 || _adminAll()) return true;
    try {
      if (typeof isSkinUnlocked === 'function') return isSkinUnlocked(idx);
    } catch(_){}
    return false;
  }

  // ── Build dropdown <option>s ─────────────────────────────────────────
  // Garage-local preview state — separate from the equipped skin saved on the
  // title screen. Lives only in memory so a fresh page load shows the
  // currently-displayed (equipped) ship first.
  let _garagePreviewIdx = null;
  function _equippedSkinIdx() {
    try { return (loadSkinData() || {}).selected || 0; } catch(_) { return 0; }
  }
  // Reverse-lookup: which SHIP_SKINS index matches the ship currently shown
  // on the title canvas? Lets garage open sync the dropdown to the canvas
  // WITHOUT firing a skin swap (which would wipe thruster anchors).
  function _displayedSkinIdx() {
    try {
      const ship = (typeof _titleShipModel !== 'undefined') ? _titleShipModel : null;
      const altFile = ship && ship.userData && ship.userData._altGlb;
      if (typeof SHIP_SKINS !== 'undefined' && Array.isArray(SHIP_SKINS)) {
        for (let i = 0; i < SHIP_SKINS.length; i++) {
          const s = SHIP_SKINS[i];
          if (!s) continue;
          if (altFile) { if (s.glbFile === altFile) return i; }
          else { if (!s.glbFile) return i; }
        }
      }
    } catch(_){}
    return _equippedSkinIdx();
  }
  // Preview a skin WITHOUT touching equipped state. We call BOTH applySkin
  // and applyTitleSkin (the same pair navigateToSkin runs) because alt-GLB
  // ships like MK Runner need applySkin's lighting reset + _showAltShip to
  // render correctly — applyTitleSkin alone leaves them invisible/black.
  // What we explicitly skip is the data.selected write that navigateToSkin
  // performs, since that's the equipped-state mutation we want to avoid.
  function _previewSkin(idx) {
    if (typeof applySkin === 'function') {
      try { applySkin(idx); } catch(_){}
    }
    if (typeof applyTitleSkin === 'function') {
      try { applyTitleSkin(idx); } catch(_){}
    }
  }

  function _buildSkinOptions(sel) {
    if (!sel) return;
    sel.innerHTML = '';
    if (typeof SHIP_SKINS === 'undefined') return;
    const reqs = _getUnlockReqs();
    // Highlight the GARAGE preview, not the equipped skin — they're separate.
    const selectedIdx = (_garagePreviewIdx != null) ? _garagePreviewIdx : _equippedSkinIdx();
    SHIP_SKINS.forEach((skin, idx) => {
      if (skin.hidden) return;
      const unlocked = _isSkinUnlockedSafe(idx);
      const opt = document.createElement('option');
      opt.value = String(idx);
      let label = (skin.name || ('SKIN ' + idx));
      if (!unlocked) {
        const m = reqs.skins[idx];
        const tag = (m ? ('M' + m) : (skin.price ? (skin.price + 'c') : 'LOCKED'));
        label += '  · ' + tag;
        opt.disabled = true;
      }
      opt.textContent = label;
      if (idx === selectedIdx) opt.selected = true;
      sel.appendChild(opt);
    });
  }

  function _buildShapeOptions(sel) {
    if (!sel) return;
    sel.innerHTML = '';
    const presets = window._THRUSTER_PRESETS || {};
    const reqs = _getUnlockReqs();
    let selectedKey = 'baseline';
    try { selectedKey = (loadThrusterData() || {}).selectedPreset || 'baseline'; } catch(_){}
    Object.keys(presets).forEach(key => {
      const P = presets[key];
      const unlocked = _isPresetUnlocked(key);
      const opt = document.createElement('option');
      opt.value = key;
      const baseLabel = (P && P.label) ? P.label.toUpperCase() : key.toUpperCase();
      let label = baseLabel;
      if (!unlocked) {
        const m = reqs.presets[key];
        label += '  · ' + (m ? ('M' + m) : 'LOCKED');
        opt.disabled = true;
      }
      opt.textContent = label;
      if (key === selectedKey) opt.selected = true;
      sel.appendChild(opt);
    });
  }

  function _buildColorOptions(sel) {
    if (!sel) return;
    sel.innerHTML = '';
    const palette = window._THRUSTER_COLOR_PALETTE || {};
    const reqs = _getUnlockReqs();
    let selectedKey = 'default';
    try { selectedKey = (loadThrusterData() || {}).selectedColor || 'default'; } catch(_){}
    Object.keys(palette).forEach(key => {
      const C = palette[key];
      const unlocked = _isColorUnlocked(key);
      const opt = document.createElement('option');
      opt.value = key;
      const baseLabel = (C && C.label) ? C.label.toUpperCase() : key.toUpperCase();
      let label = baseLabel;
      if (!unlocked) {
        const m = reqs.colors[key];
        label += '  · ' + (m ? ('M' + m) : 'LOCKED');
        opt.disabled = true;
      }
      opt.textContent = label;
      if (key === selectedKey) opt.selected = true;
      sel.appendChild(opt);
    });
  }

  function _populateAll() {
    _buildSkinOptions(document.getElementById('sr-select-skin'));
    _buildShapeOptions(document.getElementById('sr-select-shape'));
    _buildColorOptions(document.getElementById('sr-select-color'));
    _populateAddons();
  }

  // ── ADD-ONS ───────────────────────────────────────────────────────────
  // Per-GLB add-on registry. Mesh names are HARDCODED from the GLB's actual
  // node hierarchy (read from the file, not pattern-matched), and looked up
  // via traverse() so it works regardless of where they sit in the clone.
  // Default state is OFF; user toggles on. Visibility is applied AFTER the
  // ship has been placed in the scene so it never affects bbox/hullBackZ.
  const SR_ADDONS_KEY = 'jh_showroom_addons_v2';
  // GLTFLoader sanitizes node names: spaces → underscore, dots removed
  // (see three.js issue #27873). The GLB authoring tool stored names like
  // 'Fins 01' but the runtime scene has 'Fins_01'. Registry uses the
  // SANITIZED forms so _findAddonNode matches what's actually in the scene.
  // Display labels keep the spaces for readability.
  const ADDON_REGISTRY = {
    'spaceship_01.glb': [
      { node: 'Fins_01',     label: 'Fins 01' },
      { node: 'Fins_02',     label: 'Fins 02' },
      { node: 'Rings_001',   label: 'Rings 001' },
      { node: 'Turrets_001', label: 'Turrets 001' },
      { node: 'Turrets_002', label: 'Turrets 002' },
      { node: 'Turrets_003', label: 'Turrets 003' },
    ],
  };
  function _loadAddonsState() {
    try { return JSON.parse(localStorage.getItem(SR_ADDONS_KEY) || '{}') || {}; }
    catch(_) { return {}; }
  }
  function _saveAddonsState(s) {
    try { localStorage.setItem(SR_ADDONS_KEY, JSON.stringify(s || {})); } catch(_){}
  }
  function _currentAddonsKey() {
    const ship = (typeof _titleShipModel !== 'undefined') ? _titleShipModel : null;
    return (ship && ship.userData && ship.userData._altGlb) || null;
  }
  // Find a named descendant on the title ship clone. MK Runner's hull is
  // 'Cube.007' and the add-ons are its children, but we traverse so the
  // lookup works no matter how deeply nested.
  function _findAddonNode(name) {
    const ship = (typeof _titleShipModel !== 'undefined') ? _titleShipModel : null;
    if (!ship) return null;
    let hit = null;
    ship.traverse(o => { if (!hit && o.name === name) hit = o; });
    return hit;
  }
  // INTENTIONALLY a no-op for now. Earlier versions auto-applied saved
  // visibility state on ship swap, but mutating add-on visibility right
  // before _thrInit measures the bbox shifted hullBackZ — which moved RST
  // landing position. Keeping this empty guarantees the thruster system
  // never sees a hull with hidden pieces.
  function _applyAddonsToShip() { /* no-op: see comment */ }
  function _populateAddons() {
    const list = document.getElementById('sr-addons-list');
    if (!list) return;
    const key = _currentAddonsKey();
    const entries = key && ADDON_REGISTRY[key];
    if (!entries || !entries.length) {
      list.innerHTML = '<div class="sr-addon-empty">No add-ons available for this ship</div>';
      return;
    }
    let html = '';
    entries.forEach(entry => {
      const node = _findAddonNode(entry.node);
      const checked = node ? !!node.visible : true;
      const nodeName = String(entry.node).replace(/"/g, '&quot;');
      const label = String(entry.label).replace(/</g, '&lt;');
      html += '<label class="sr-addon-row">'+
        '<input type="checkbox" data-addon="'+nodeName+'" '+(checked?'checked':'')+'>'+
        '<span>'+label+'</span>'+
      '</label>';
    });
    list.innerHTML = html;
    list.querySelectorAll('input[type="checkbox"][data-addon]').forEach(inp => {
      inp.addEventListener('change', (e) => {
        const k = _currentAddonsKey();
        if (!k) return;
        const n = e.target.dataset.addon;
        const visible = !!e.target.checked;
        const node = _findAddonNode(n);
        if (node) node.visible = visible;
        const s = _loadAddonsState();
        if (!s[k]) s[k] = {};
        s[k][n] = visible;
        _saveAddonsState(s);
      });
    });
  }
  // Show the ADD-ONS tab only when the current ship has add-ons registered.
  // Other ships hide the tab entirely so we never show an empty pane.
  function _refreshAddonsTabVisibility() {
    const tab = document.querySelector('.sr-tab[data-tab="addons"]');
    if (!tab) return;
    const key = _currentAddonsKey();
    const reg = key && ADDON_REGISTRY[key];
    const has = !!(reg && reg.length);
    tab.classList.toggle('sr-hidden', !has);
    // If the active tab just got hidden, fall back to thrusters.
    if (!has && _activeTab === 'addons') _switchTab('thrusters');
  }

  // ── Wire dropdown change handlers ────────────────────────────────────
  function _onSkinChange(e) {
    const idx = parseInt(e.target.value, 10);
    if (isNaN(idx)) return;
    // Garage selection is preview-only — do NOT write data.selected. The
    // equipped skin only changes when the player explicitly hits USE on the
    // title screen's skin viewer.
    _garagePreviewIdx = idx;
    _previewSkin(idx);
    // Skin swap may load a new GLB whose materials default to transparent.
    requestAnimationFrame(() => { try { _forceShipOpaque(); } catch(_){} });
    // The new ship may or may not have add-ons — refresh the tab + list.
    try { _refreshAddonsTabVisibility(); _populateAddons(); } catch(_){}
    try { playTitleTap(); } catch(_){}
  }

  function _onShapeChange(e) {
    const key = e.target.value;
    if (!key) return;
    try {
      const d = loadThrusterData();
      if (!d.unlockedPresets.includes(key)) d.unlockedPresets.push(key);
      d.selectedPreset = key;
      saveThrusterData(d);
      if (typeof window._applyEquippedThruster === 'function') window._applyEquippedThruster();
    } catch(_){}
    // Re-sync color (preset apply may have set a new tint) and let the
    // tick loop pick up the new knobs on the next frame.
    _thrSyncColor();
    try { playTitleTap(); } catch(_){}
  }

  function _onColorChange(e) {
    const key = e.target.value;
    if (!key) return;
    try {
      const d = loadThrusterData();
      if (!d.unlockedColors.includes(key)) d.unlockedColors.push(key);
      d.selectedColor = key;
      saveThrusterData(d);
      if (typeof window._applyEquippedThruster === 'function') window._applyEquippedThruster();
    } catch(_){}
    // Sync showroom preview color immediately.
    _thrSyncColor();
    try { playTitleTap(); } catch(_){}
  }

  // ── Tab switching ────────────────────────────────────────────────────
  function _switchTab(tab) {
    _activeTab = tab;
    document.querySelectorAll('.sr-tab').forEach(t => {
      t.classList.toggle('active', t.dataset.tab === tab);
    });
    document.querySelectorAll('.sr-pane').forEach(p => {
      p.classList.toggle('sr-hidden', p.dataset.pane !== tab);
    });
  }

  function _onTabClick(e) {
    const t = e.currentTarget;
    if (t.classList.contains('sr-hidden')) return;
    try { playTitleTap(); } catch(_){}
    _switchTab(t.dataset.tab);
  }

  // ── One-time wiring (idempotent) ─────────────────────────────────────
  function _wireOnce() {
    if (_wired) return;
    _wired = true;
    document.querySelectorAll('.sr-tab').forEach(t => {
      t.addEventListener('click', _onTabClick);
    });
    const sSkin  = document.getElementById('sr-select-skin');
    const sShape = document.getElementById('sr-select-shape');
    const sColor = document.getElementById('sr-select-color');
    if (sSkin)  sSkin.addEventListener('change', _onSkinChange);
    if (sShape) sShape.addEventListener('change', _onShapeChange);
    if (sColor) sColor.addEventListener('change', _onColorChange);
  }

  // ── Canvas relocation: detach title-ship-canvas to fullscreen stage ──
  // The render loop in 70-perf-diag.js calls _titleRenderer.render() every
  // frame regardless of canvas position, so just resizing+reparenting the
  // canvas + updating the camera aspect = bigger ship preview, no other code.
  function _relocateCanvasToStage() {
    const canvas = document.getElementById('title-ship-canvas');
    const stage  = document.getElementById('sr-stage');
    if (!canvas || !stage) return;
    if (_canvasSaved) return; // already relocated
    _canvasSaved = {
      parent: canvas.parentNode,
      nextSibling: canvas.nextSibling,
      styleW: canvas.style.width,
      styleH: canvas.style.height,
      styleTransform: canvas.style.transform,
      styleMaxWidth: canvas.style.maxWidth,
      styleMaxHeight: canvas.style.maxHeight,
      camAspect: (typeof titleCamera !== 'undefined' && titleCamera) ? titleCamera.aspect : null,
      rendererW: 0, rendererH: 0,
    };
    // Capture current renderer drawing-buffer size.
    try {
      if (typeof _titleRenderer !== 'undefined' && _titleRenderer) {
        const sz = new THREE.Vector2();
        _titleRenderer.getSize(sz);
        _canvasSaved.rendererW = sz.x;
        _canvasSaved.rendererH = sz.y;
      }
    } catch(_){}
    // Detach + clear inline transform/size so stage CSS controls layout.
    canvas.style.transform = '';
    canvas.style.width = '100%';
    canvas.style.height = '100%';
    canvas.style.maxWidth = '';
    canvas.style.maxHeight = '';
    stage.appendChild(canvas);
    _resizeStageCanvas();
    // Override ship pose for showroom: force horizontal (side-profile) tilt
    // in BOTH portrait and landscape so thrusters are visible. The live title
    // screen restores its own pose on close.
    try {
      const pivot = (typeof titleScene !== 'undefined') ? titleScene.getObjectByName('titleShipPivot') : null;
      const tiltGroup = pivot && pivot.children && pivot.children[0];
      if (tiltGroup) {
        _canvasSaved.tiltX = tiltGroup.rotation.x;
        _canvasSaved.tiltY = tiltGroup.rotation.y;
        _canvasSaved.tiltZ = tiltGroup.rotation.z;
        tiltGroup.rotation.x = 0.13;
        tiltGroup.rotation.y = 0;
        tiltGroup.rotation.z = 0;
      }
    } catch(_){}
  }

  function _restoreCanvas() {
    const canvas = document.getElementById('title-ship-canvas');
    if (!canvas || !_canvasSaved) return;
    const s = _canvasSaved;
    canvas.style.width  = s.styleW || '';
    canvas.style.height = s.styleH || '';
    canvas.style.transform = s.styleTransform || '';
    canvas.style.maxWidth = s.styleMaxWidth || '';
    canvas.style.maxHeight = s.styleMaxHeight || '';
    if (s.parent) {
      if (s.nextSibling && s.nextSibling.parentNode === s.parent) {
        s.parent.insertBefore(canvas, s.nextSibling);
      } else {
        s.parent.appendChild(canvas);
      }
    }
    // Restore renderer + camera to their pre-open dimensions.
    try {
      if (typeof _titleRenderer !== 'undefined' && _titleRenderer && s.rendererW && s.rendererH) {
        _titleRenderer.setSize(s.rendererW, s.rendererH, false);
      }
      if (typeof titleCamera !== 'undefined' && titleCamera && s.camAspect) {
        titleCamera.aspect = s.camAspect;
        titleCamera.updateProjectionMatrix();
      }
      // Restore ship pose.
      const pivot = (typeof titleScene !== 'undefined') ? titleScene.getObjectByName('titleShipPivot') : null;
      const tiltGroup = pivot && pivot.children && pivot.children[0];
      if (tiltGroup && typeof s.tiltX === 'number') {
        tiltGroup.rotation.x = s.tiltX;
        tiltGroup.rotation.y = s.tiltY || 0;
        tiltGroup.rotation.z = s.tiltZ || 0;
      }
    } catch(_){}
    _canvasSaved = null;
  }

  // Resize the showroom stage canvas to fit the stage element + update camera.
  function _resizeStageCanvas() {
    const canvas = document.getElementById('title-ship-canvas');
    const stage  = document.getElementById('sr-stage');
    if (!canvas || !stage || !_canvasSaved) return; // only while relocated
    const r = stage.getBoundingClientRect();
    const w = Math.max(64, Math.floor(r.width));
    const h = Math.max(64, Math.floor(r.height));
    const dpr = Math.min(window.devicePixelRatio || 1, 2);
    try {
      if (typeof _titleRenderer !== 'undefined' && _titleRenderer) {
        _titleRenderer.setPixelRatio(dpr);
        _titleRenderer.setSize(w, h, false);
      }
      if (typeof titleCamera !== 'undefined' && titleCamera) {
        titleCamera.aspect = w / h;
        titleCamera.updateProjectionMatrix();
      }
    } catch(_){}
    canvas.style.width  = w + 'px';
    canvas.style.height = h + 'px';
  }

  function _onResize() {
    if (!_open) return;
    _resizeStageCanvas();
  }

  // ─── Showroom thruster preview: build, tick, show/hide ─────────────
  // Builds 2 particle systems + 2 bloom sprites in titleScene, mirroring the
  // gameplay particle/bloom code path with showroom-fixed inputs.
  function _makeBloomTex() {
    const size = 64;
    const c = document.createElement('canvas');
    c.width = c.height = size;
    const ctx = c.getContext('2d');
    const g = ctx.createRadialGradient(size/2, size/2, 0, size/2, size/2, size/2);
    g.addColorStop(0,   'rgba(255,255,255,1.0)');
    g.addColorStop(0.2, 'rgba(255,255,255,0.6)');
    g.addColorStop(0.5, 'rgba(255,255,255,0.15)');
    g.addColorStop(1.0, 'rgba(255,255,255,0.0)');
    ctx.fillStyle = g;
    ctx.fillRect(0, 0, size, size);
    return new THREE.CanvasTexture(c);
  }

  // One-shot: ensure window._THRUSTER_PRESETS.baseline holds a real snapshot
  // of the current live values so selecting 'baseline' after another preset
  // actually restores. Mirrors the dev tuner's _captureLiveThrValues but does
  // not require opening the G-key panel.
  function _captureBaselineIfMissing() {
    try {
      const presets = window._THRUSTER_PRESETS || {};
      if (presets.baseline) return;
      const allKeys = new Set();
      Object.values(presets).forEach(p => { if (p) Object.keys(p).forEach(k => allKeys.add(k)); });
      const snap = { label: 'BASELINE' };
      allKeys.forEach(k => {
        if (k === 'label') return;
        if (k === '_pointMatSize') {
          try { if (window.thrusterSystems && window.thrusterSystems[0]) snap[k] = window.thrusterSystems[0].points.material.size; } catch(_){}
        } else if (k === '_miniPointMatSize') {
          try { if (window.miniThrusterSystems && window.miniThrusterSystems[0]) snap[k] = window.miniThrusterSystems[0].points.material.size; } catch(_){}
        } else if (k === 'nozL' || k === 'nozR') {
          if (typeof NOZZLE_OFFSETS !== 'undefined' && NOZZLE_OFFSETS[0]) {
            const v = (k === 'nozL') ? NOZZLE_OFFSETS[0] : NOZZLE_OFFSETS[1];
            snap[k] = [v.x, v.y, v.z];
          }
        } else if (k.charAt(0) === '_') {
          if (window[k] != null) snap[k] = window[k];
        }
      });
      presets.baseline = snap;
    } catch(_){}
  }

  // Build one particle+bloom system in titleScene; returns its handle.
  function _buildPodSystem(N, tex, isMini) {
    const positions  = new Float32Array(N * 3);
    const colors     = new Float32Array(N * 3);
    const sizes      = new Float32Array(N);
    const velocities = [];
    const age        = new Float32Array(N);
    const life       = new Float32Array(N);
    for (let i = 0; i < N; i++) {
      age[i] = Math.random();
      life[i] = SR_DEFAULTS.lifeMin + Math.random() * SR_DEFAULTS.lifeJit;
      velocities.push(new THREE.Vector3());
    }
    const geo = new THREE.BufferGeometry();
    geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    geo.setAttribute('color',    new THREE.BufferAttribute(colors,    3));
    geo.setAttribute('size',     new THREE.BufferAttribute(sizes,     1));
    const mat = new THREE.PointsMaterial({
      size: isMini ? 0.08 : 0.13,
      map: tex,
      vertexColors: true,
      transparent: true,
      opacity: 1.0,
      depthWrite: false,
      depthTest: true, // z-test against ship hull so additive bloom doesn't blow out the hull
      blending: THREE.AdditiveBlending,
      sizeAttenuation: true,
    });
    const pts = new THREE.Points(geo, mat);
    pts.frustumCulled = false;
    pts.renderOrder = isMini ? 12 : 10;
    pts.visible = false;
    titleScene.add(pts);
    const bMat = new THREE.SpriteMaterial({
      map: tex, color: 0xffffff, transparent: true, opacity: 0,
      depthWrite: false, depthTest: true, blending: THREE.AdditiveBlending,
    });
    const bSpr = new THREE.Sprite(bMat);
    bSpr.frustumCulled = false;
    bSpr.renderOrder = isMini ? 13 : 11;
    bSpr.visible = false;
    titleScene.add(bSpr);
    return { points: pts, geo, positions, colors, sizes, velocities, ages: age, lifetimes: life, bloom: bSpr, isMini };
  }

  function _thrInit() {
    if (_thr) return;
    if (typeof titleScene === 'undefined' || !titleScene) return;
    if (typeof NOZZLE_OFFSETS === 'undefined' || !NOZZLE_OFFSETS) return;
    _captureBaselineIfMissing();
    const tex = _makeBloomTex();
    // 4 pod systems: main L, main R, mini L, mini R.
    const NB = SR_PARTICLE_COUNT;
    const NM = Math.max(40, Math.floor(SR_PARTICLE_COUNT * 0.6));
    const groups = {
      L:  _buildPodSystem(NB, tex, false),
      R:  _buildPodSystem(NB, tex, false),
      mL: _buildPodSystem(NM, tex, true),
      mR: _buildPodSystem(NM, tex, true),
    };
    if (!_tuner) _tuner = _loadTuner();
    const ship = (typeof _titleShipModel !== 'undefined') ? _titleShipModel : null;
    const anchors = {};
    ['L','R','mL','mR'].forEach(k => {
      const a = new THREE.Object3D();
      a.name = 'sr_anchor_' + k;
      anchors[k] = a;
      if (ship) ship.add(a); else titleScene.add(a);
    });
    // Auto-detect hull back-Z in ship-LOCAL space so tuner.z=0 sits at the
    // visible hull back. Default Runner: simple world-bbox → worldToLocal,
    // pick more-negative local Z (matches pre-bac0720 behavior the user
    // confirmed worked). MK Runner / alt-GLB: same, then we let the user
    // tune separately because their GLB shape lays out differently.
    // hullBackZ is intentionally a CONSTANT. Tuner offsets are absolute
    // anchor positions in ship-local space, plus this fixed back-Z origin.
    // Measuring per-ship caused the thrusters to drift on swap because
    // bbox depended on async matrix updates and child geometry. The
    // user-confirmed working value for the default Runner is -2.394, and
    // the same tuner reproduces correctly on MK Runner with the same value.
    const hullBackZ = -2.394;
    _thr = {
      groups,           // { L, R, mL, mR }
      anchors,          // { L, R, mL, mR }
      color: new THREE.Color(0x66ccff),
      _v: new THREE.Vector3(),
      hullBackZ,
    };
    _applyTunerToAnchors();
  }

  // Push tuner state into the anchor Object3Ds. Anchor local Z is
  // hullBackZ + tuner.z so tuner.z == 0 sits at the visible hull back.
  // Pitch/yaw are converted to a quaternion so anchor's local -Z direction
  // (the exhaust direction) tilts — we read it via getWorldDirection in tick.
  const _DEG2RAD = Math.PI / 180;
  function _applyTunerToAnchors() {
    if (!_thr || !_thr.anchors || !_tuner) return;
    const hz = _thr.hullBackZ || 0;
    ['L','R','mL','mR'].forEach(k => {
      const t = _tuner[k]; const a = _thr.anchors[k];
      if (!t || !a) return;
      a.position.set(t.x, t.y, hz + t.z);
      // Pitch around X (looking at side profile, +pitch tilts exhaust upward).
      // Yaw around Y (+yaw rotates exhaust toward +X).
      a.rotation.set((t.pitch||0) * _DEG2RAD, (t.yaw||0) * _DEG2RAD, 0);
    });
  }

  // ── Tuner + FX HUDs live in src/49-tuner-hud.js ─────────────────
  // The HUD module owns DOM/event wiring; we own state. Bind the api once
  // on first show, then call into window.TunerHud for visibility toggles.
  let _tunerHudInited = false;
  function _ensureTunerHudInit() {
    if (_tunerHudInited) return;
    if (!window.TunerHud || typeof window.TunerHud.init !== 'function') return;
    window.TunerHud.init({
      getTuner:        function(){ return _tuner; },
      setTuner:        function(t){ _tuner = t; _tunerLoadedKey = _currentTunerKey(); },
      getDefaults:     function(){ return SR_TUNER_DEFAULT; },
      getThr:          function(){ return _thr; },
      isOpen:          function(){ return _open; },
      save:            _saveTuner,
      applyToAnchors:  _applyTunerToAnchors,
      getTitleCamera:  function(){ return (typeof titleCamera !== 'undefined') ? titleCamera : null; },
    });
    _tunerHudInited = true;
  }
  function _showTuner(show) {
    _ensureTunerHudInit();
    if (window.TunerHud) window.TunerHud.showTuner(show);
  }
  function _showFx(show) {
    _ensureTunerHudInit();
    if (window.TunerHud) window.TunerHud.showFx(show);
  }
  function _updateTunerHud() {
    if (window.TunerHud && window.TunerHud.updateTuner) window.TunerHud.updateTuner();
  }


  function _thrShow(visible) {
    if (!_thr) return;
    Object.values(_thr.groups).forEach(g => {
      g.points.visible = !!visible;
      g.bloom.visible = !!visible;
    });
  }

  // Read the equipped color from storage and update the cached color.
  function _thrSyncColor() {
    if (!_thr) return;
    let key = 'default';
    try { key = (loadThrusterData() || {}).selectedColor || 'default'; } catch(_){}
    const palette = window._THRUSTER_COLOR_PALETTE || {};
    const entry = palette[key];
    // 'default' (hex null) — use a neutral cyan-white so the preview reads;
    // gameplay's 'default' inherits whatever color the run started with, but
    // for a static showroom we pick a sensible fallback.
    if (!entry || entry.hex == null) {
      _thr.color.setRGB(0.55, 0.85, 1.0);
    } else {
      _thr.color.set(entry.hex);
    }
  }

  // Per-frame tick. Mirrors updateThrusters() particle + bloom logic with
  // showroom-fixed inputs (no shipGroup, no state.speed, no state.shipVelX).
  function _thrTick(dt) {
    if (!_thr || !_open) return;
    // Find the title ship pivot — we transform NOZZLE_OFFSETS through its
    // world matrix to get nozzle world positions every frame (cheap).
    if (typeof titleScene === 'undefined' || !titleScene) return;
    const ship = (typeof _titleShipModel !== 'undefined') ? _titleShipModel : null;
    if (!ship) return;
    ship.updateMatrixWorld(true);

    // Read knobs (preset writes these onto window.* via _writeThrPresetValues)
    const D = SR_DEFAULTS;
    const posPinFrac = (window._thrPart_posPinFrac != null) ? window._thrPart_posPinFrac : D.posPinFrac;
    const lifeMin   = (window._thrPart_lifeMin   != null) ? window._thrPart_lifeMin   : D.lifeMin;
    const lifeJit   = (window._thrPart_lifeJit   != null) ? window._thrPart_lifeJit   : D.lifeJit;
    const lifeBase  = (window._thrPart_lifeBase  != null) ? window._thrPart_lifeBase  : D.lifeBase;
    const lifeSpd   = (window._thrPart_lifeSpd   != null) ? window._thrPart_lifeSpd   : D.lifeSpd;
    const spawnJit  = (window._thrPart_spawnJit  != null) ? window._thrPart_spawnJit  : D.spawnJit;
    const coreEnd   = (window._thrPart_coreEnd   != null) ? window._thrPart_coreEnd   : D.coreEnd;
    const coreR     = (window._thrPart_coreR     != null) ? window._thrPart_coreR     : D.coreR;
    const coreGB    = (window._thrPart_coreGB    != null) ? window._thrPart_coreGB    : D.coreGB;
    const midEnd    = (window._thrPart_midEnd    != null) ? window._thrPart_midEnd    : D.midEnd;
    const midBoost  = (window._thrPart_midBoost  != null) ? window._thrPart_midBoost  : D.midBoost;
    const szBase    = (window._thrPart_sizeBase  != null) ? window._thrPart_sizeBase  : D.sizeBase;
    const szSpeed   = (window._thrPart_sizeSpeed != null) ? window._thrPart_sizeSpeed : D.sizeSpeed;
    const bumpMult  = (window._thrPart_bumpMult  != null) ? window._thrPart_bumpMult  : D.bumpMult;
    const bumpEnd   = (window._thrPart_bumpEnd   != null) ? window._thrPart_bumpEnd   : D.bumpEnd;
    const szJitter  = (window._thrPart_sizeJitter!= null) ? window._thrPart_sizeJitter: D.sizeJitter;
    const partOp    = (window._thrPart_partOpacity != null) ? window._thrPart_partOpacity : D.partOpacity;
    const thrScale  = (window._thrusterScale     != null) ? window._thrusterScale     : 1.0;
    const pointSize = (window._THRUSTER_PRESETS && window._activeThrusterPreset && window._THRUSTER_PRESETS[window._activeThrusterPreset] && window._THRUSTER_PRESETS[window._activeThrusterPreset]._pointMatSize) || 0.13;
    const bloomWM   = (window._nozzleBloom_whiteMix != null) ? window._nozzleBloom_whiteMix : D.bloomWhiteMix;
    const bloomPul  = (window._nozzleBloomPulse  != null) ? window._nozzleBloomPulse  : D.bloomPulse;

    // Showroom-only fx overrides (gated to this preview only — never leak to gameplay).
    const fx        = (_tuner && _tuner.fx) || SR_TUNER_DEFAULT.fx;
    const bloomScl  = fx.bloomScale;
    const bloomOp   = fx.bloomOpacity;
    const fxPartSz  = fx.partSize;
    const fxPartOp  = fx.partOpacity;
    const fxLifeB   = fx.lifeBase;
    const fxLifeJ   = fx.lifeJit;
    const fxMiniSz  = fx.miniSize;
    const fxMiniBl  = fx.miniBloom;

    const tCol = _thr.color;
    const ss = SR_SPEED_SCALE;
    const tp = SR_TP;
    const flipSign = _tuner.flip ? 1 : -1;  // -1 = exhaust into anchor -Z (default)
    const _exhDir = new THREE.Vector3();

    const KEYS = ['L','R','mL','mR'];
    for (let ki = 0; ki < KEYS.length; ki++) {
      const k = KEYS[ki];
      const g = _thr.groups[k];
      const a = _thr.anchors[k];
      const tu = _tuner[k];
      if (!g || !a || !tu) continue;
      const isMini = !!g.isMini;
      const N = g.positions.length / 3 | 0;

      // World position of the nozzle anchor.
      a.getWorldPosition(_thr._v);
      const wx = _thr._v.x, wy = _thr._v.y, wz = _thr._v.z;
      // World direction the anchor's local -Z points to (this is exhaust dir).
      a.getWorldDirection(_exhDir); // returns world +Z forward
      // Three's getWorldDirection gives the +Z axis of the object; exhaust is -Z
      // when flip=false. Multiply by flipSign so 'flip' inverts the exhaust dir.
      const exhX = flipSign * _exhDir.x;
      const exhY = flipSign * _exhDir.y;
      const exhZ = flipSign * _exhDir.z;

      const aScale = tu.scale || 1.0;
      const baseSizeMult  = (isMini ? fxMiniSz : 1.0) * fxPartSz;
      const baseBloomMult = (isMini ? fxMiniBl : 1.0);

      // Particle material size.
      const matSize = pointSize * aScale * baseSizeMult;
      if (g.points.material.size !== matSize) g.points.material.size = matSize;
      const wantOp = partOp * fxPartOp;
      if (g.points.material.opacity !== wantOp) g.points.material.opacity = wantOp;

      const pos = g.positions, col = g.colors, sz = g.sizes;
      for (let i = 0; i < N; i++) {
        g.ages[i] += dt;
        if (g.ages[i] >= g.lifetimes[i]) {
          g.ages[i] = 0;
          g.lifetimes[i] = (lifeMin + Math.random() * fxLifeJ) * (fxLifeB + ss * lifeSpd);
          pos[i*3]     = wx + (Math.random() - 0.5) * spawnJit;
          pos[i*3 + 1] = wy + (Math.random() - 0.5) * spawnJit;
          pos[i*3 + 2] = wz;
          // Velocity = exhaust direction × speed + small jitter perpendicular.
          const sp = (2.5 + Math.random() * 2.0 + ss * 1.5) * aScale;
          g.velocities[i].set(
            exhX * sp + (Math.random() - 0.5) * 0.06 * aScale,
            exhY * sp + (Math.random() - 0.5) * 0.06 * aScale - 0.02 * aScale,
            exhZ * sp
          );
        } else {
          const t0 = g.ages[i] / g.lifetimes[i];
          if (t0 < posPinFrac) {
            pos[i*3] = wx; pos[i*3 + 1] = wy; pos[i*3 + 2] = wz;
          } else {
            const v = g.velocities[i];
            pos[i*3]     += v.x * dt;
            pos[i*3 + 1] += v.y * dt;
            pos[i*3 + 2] += v.z * dt;
            v.multiplyScalar(0.92);
          }
        }
        const t = g.ages[i] / g.lifetimes[i];
        if (t < coreEnd) {
          const s = t / coreEnd;
          col[i*3]     = coreR;
          col[i*3 + 1] = THREE.MathUtils.lerp(coreGB, tCol.g, s);
          col[i*3 + 2] = THREE.MathUtils.lerp(coreGB, tCol.b, s);
        } else if (t < midEnd) {
          const s = (t - coreEnd) / Math.max(0.001, (midEnd - coreEnd));
          const bright = 1.0 + ss * midBoost;
          col[i*3]     = THREE.MathUtils.lerp(tCol.r * bright, tCol.r, s);
          col[i*3 + 1] = THREE.MathUtils.lerp(tCol.g * bright, tCol.g, s);
          col[i*3 + 2] = THREE.MathUtils.lerp(tCol.b * bright, tCol.b, s);
        } else {
          const s = (t - midEnd) / Math.max(0.001, (1.0 - midEnd));
          col[i*3]     = THREE.MathUtils.lerp(tCol.r, 0, s);
          col[i*3 + 1] = THREE.MathUtils.lerp(tCol.g, 0, s);
          col[i*3 + 2] = THREE.MathUtils.lerp(tCol.b, 0, s);
        }
        const baseSize = szBase + ss * szSpeed;
        const rawSz = t < bumpEnd
          ? THREE.MathUtils.lerp(baseSize * bumpMult, baseSize, t / bumpEnd)
          : (1.0 - t) * (baseSize + Math.random() * szJitter);
        sz[i] = rawSz * tp * thrScale * baseSizeMult;
      }
      g.geo.attributes.position.needsUpdate = true;
      g.geo.attributes.color.needsUpdate    = true;
      g.geo.attributes.size.needsUpdate     = true;

      g.bloom.position.set(wx, wy, wz);
      const bloomSize = (0.6 + ss * 0.7) * thrScale * bloomScl * aScale * baseBloomMult;
      g.bloom.scale.setScalar(bloomSize);
      g.bloom.material.color.setRGB(
        THREE.MathUtils.lerp(tCol.r, 1.0, bloomWM),
        THREE.MathUtils.lerp(tCol.g, 1.0, bloomWM),
        THREE.MathUtils.lerp(tCol.b, 1.0, bloomWM)
      );
      g.bloom.material.opacity = bloomOp * ((1 - bloomPul) + Math.sin(Date.now() * 0.008) * bloomPul) * tp;
    }
  }

  // Force the title ship's materials to fully opaque so the GLB doesn't
  // appear transparent in the showroom preview. Re-runs whenever a new
  // shape/skin is loaded by the showroom open hook.
  function _forceShipOpaque() {
    const ship = (typeof _titleShipModel !== 'undefined') ? _titleShipModel : null;
    if (!ship) return;
    ship.traverse((o) => {
      if (!o || !o.isMesh) return;
      const mats = Array.isArray(o.material) ? o.material : [o.material];
      for (let i = 0; i < mats.length; i++) {
        const m = mats[i]; if (!m) continue;
        // Skip skins that legitimately need transparency (Ghost holo + any
        // custom ShaderMaterial that uses transparency as part of its look).
        if (m.uniforms && m.uniforms.hologramColor) continue;
        if (m.isShaderMaterial || m.isRawShaderMaterial) continue;
        if (m.transparent) m.transparent = false;
        if (m.opacity !== 1) m.opacity = 1;
        if (m.depthWrite === false) m.depthWrite = true;
        if (m.alphaTest && m.alphaTest > 0) m.alphaTest = 0;
        m.needsUpdate = true;
      }
    });
  }

  // ── Public: open / close / refresh ───────────────────────────────────
  function open(tab) {
    const overlay = document.getElementById('thruster-overlay');
    if (!overlay) return;
    _wireOnce();
    overlay.classList.remove('hidden');
    document.body.classList.add('sr-open');
    _switchTab(tab || 'thrusters');
    // Seed the garage preview index from whatever ship is currently on the
    // title canvas. Keeps the dropdown in sync with the visible ship without
    // firing a skin swap (which would wipe thruster anchors).
    _garagePreviewIdx = _displayedSkinIdx();
    _populateAll();
    _refreshAddonsTabVisibility();
    // Relocate after the overlay is visible so getBoundingClientRect is right.
    requestAnimationFrame(() => {
      _relocateCanvasToStage();
      if (!_resizeBound) {
        _resizeBound = true;
        window.addEventListener('resize', _onResize);
        window.addEventListener('orientationchange', _onResize);
      }
      // Init thruster preview lazily on first open + show it.
      _thrInit();
      _forceShipOpaque();
      _thrSyncColor();
      _thrShow(true);
      _showTuner(true);
      _showFx(true);
    });
    _open = true;
  }

  function close() {
    const overlay = document.getElementById('thruster-overlay');
    _restoreCanvas();
    if (overlay) overlay.classList.add('hidden');
    document.body.classList.remove('sr-open');
    _open = false;
    // Hide preview immediately so it never shows on the live title screen.
    _thrShow(false);
    _showTuner(false);
    _showFx(false);
    // If the player previewed a different skin in the garage but never hit
    // USE on the title, snap the title canvas back to the equipped skin.
    if (_garagePreviewIdx != null && _garagePreviewIdx !== _equippedSkinIdx()) {
      try { _previewSkin(_equippedSkinIdx()); } catch(_){}
    }
  }

  function refresh() {
    if (!_open) return;
    _unlockReqCache = null; // recompute in case missions changed
    _populateAll();
    _thrSyncColor();
  }

  // Public tick — called from the title-phase render loop in 70-perf-diag.js,
  // which guards by checking window.Showroom?._open before invoking. When the
  // showroom is closed, the body of _thrTick early-returns, so this is free.
  function tick(dt) { _thrTick(dt); }

  // Public color sync — called by _onColorChange so dropdown updates the preview
  // without needing a full open/close cycle.
  function syncColor() { _thrSyncColor(); }

  // Drop all thruster anchors + systems so the next _thrInit() rebuilds them
  // against the (possibly swapped) _titleShipModel. Called by applyTitleSkin
  // when an alt-GLB skin is loaded.
  function resetThrusterAnchors() {
    if (!_thr) return;
    try {
      Object.values(_thr.groups || {}).forEach(g => {
        if (g.points && g.points.parent) g.points.parent.remove(g.points);
        if (g.bloom  && g.bloom.parent)  g.bloom.parent.remove(g.bloom);
      });
      Object.values(_thr.anchors || {}).forEach(a => {
        if (a && a.parent) a.parent.remove(a);
      });
    } catch(_){}
    _thr = null;
    // Swap the working tuner to the new ship's bucket BEFORE _thrInit so
    // _applyTunerToAnchors uses the right per-ship pod offsets. Persists
    // the outgoing ship's edits to its own key, never crosses streams.
    try { _swapTunerForCurrentShip(); } catch(_){}
    try { if (typeof _updateTunerHud === 'function') _updateTunerHud(); } catch(_){}
    // Apply persisted add-on visibility to the freshly-swapped ship parts.
    try { _applyAddonsToShip(); } catch(_){}
    if (_open) {
      _thrInit();
      try { _forceShipOpaque(); } catch(_){}
      _thrSyncColor();
      _thrShow(true);
    }
  }

  window.Showroom = {
    open: open, close: close, refresh: refresh,
    tick: tick, syncColor: syncColor,
    resetThrusterAnchors: resetThrusterAnchors,
    isOpen: function() { return _open; },
  };
})();
// ── TUNER + FX HUDs (showroom-only) ─────────────────────────────────────
//
// This module owns the floating tuner panel (drag/wheel/RST/MIR/FLP/ROT)
// and the FX slider stack. All state still lives in the showroom; this
// module only renders + dispatches deltas back through a bound `api`.
//
// PUBLIC: window.TunerHud = {
//   init(api),       // one-time wiring; api carries getters/setters
//   showTuner(bool), // toggle tuner HUD
//   showFx(bool),    // toggle FX HUD
//   updateTuner(),   // refresh tuner readout + button highlights
// }
//
// The api contract (every field required):
//   getTuner()            -> _tuner reference (mutated in place)
//   setTuner(obj)         -> replaces _tuner whole (used by RST)
//   getDefaults()         -> SR_TUNER_DEFAULT (read-only template)
//   getThr()              -> _thr or null
//   isOpen()              -> bool, showroom open state
//   save()                -> persists current _tuner to localStorage
//   applyToAnchors()      -> push tuner state into anchor Object3Ds
//   getTitleCamera()      -> THREE.Camera or null (for screen-to-local math)
//
// Why a module: keeps slider HTML/CSS/event noise out of 48-showroom.js so
// edits there don't risk regressing thruster anchor or skin-swap logic.
// As more sliders are added (gameplay tuning, mission balance, etc.) they
// go here, not in showroom.
(function(){
  'use strict';

  let _api = null;          // bound on init()
  let _tunerHud = null;
  let _tunerDragging = false;
  let _tunerWired = false;
  let _fxHud = null;

  // Reusable scratch vectors so we don't churn allocations on every mousemove.
  // Lazy-init to avoid touching THREE before it's loaded.
  let _v1 = null, _v2 = null;
  function _ensureScratch() {
    if (!_v1) _v1 = new THREE.Vector3();
    if (!_v2) _v2 = new THREE.Vector3();
  }

  // Mirror partner mapping: dragging L mirrors to R; dragging mL to mR.
  const _MIRROR_PAIR = { L: 'R', R: 'L', mL: 'mR', mR: 'mL' };

  const _FX_DEFS = [
    { key:'bloomScale',   lbl:'bloom scale',    min:0,    max:2.0, step:0.01 },
    { key:'bloomOpacity', lbl:'bloom opacity',  min:0,    max:1.0, step:0.01 },
    { key:'partSize',     lbl:'particle size',  min:0.1,  max:3.0, step:0.01 },
    { key:'partOpacity',  lbl:'particle alpha', min:0,    max:1.0, step:0.01 },
    { key:'lifeBase',     lbl:'trail length',   min:0.1,  max:2.0, step:0.01 },
    { key:'lifeJit',      lbl:'trail jitter',   min:0,    max:1.0, step:0.01 },
    { key:'miniSize',     lbl:'mini size mult', min:0.1,  max:2.0, step:0.01 },
    { key:'miniBloom',    lbl:'mini bloom mult',min:0,    max:2.0, step:0.01 },
  ];

  // ── Tuner HUD ──────────────────────────────────────────────────────
  function _ensureTunerHud() {
    if (_tunerHud) return _tunerHud;
    const el = document.createElement('div');
    el.id = 'sr-tuner-hud';
    el.style.cssText = [
      'position:fixed','top:8px','left:8px','z-index:99999',
      'font:12px/1.35 ui-monospace,Menlo,monospace','color:#cef',
      'background:rgba(0,12,24,0.82)','border:1px solid #3af','padding:8px 10px',
      'border-radius:6px','user-select:none','pointer-events:auto',
      'min-width:240px','box-shadow:0 0 12px rgba(60,180,255,0.25)'
    ].join(';');
    const btn = (a, lbl, danger) =>
      '<button data-act="'+a+'" style="flex:1;background:'+(danger?'#411':'#114')+';color:'+(danger?'#fcc':'#9cf')+';border:1px solid '+(danger?'#f55':'#3af')+';padding:3px 6px;border-radius:3px;cursor:pointer;min-width:32px">'+lbl+'</button>';
    el.innerHTML = [
      '<div style="font-weight:700;color:#7df;margin-bottom:4px;letter-spacing:1px">THRUSTER TUNER</div>',
      '<div id="sr-tu-readout" style="white-space:pre;font-size:11px"></div>',
      '<div style="display:flex;gap:4px;margin-top:6px;flex-wrap:wrap">',
        btn('sel-L','L'), btn('sel-R','R'), btn('sel-mL','mL'), btn('sel-mR','mR'),
      '</div>',
      '<div style="display:flex;gap:4px;margin-top:4px;flex-wrap:wrap">',
        btn('mirror','MIR'), btn('flip','FLP'), btn('rot','ROT'), btn('reset','RST', true),
      '</div>',
      '<div style="font-size:10px;color:#7af;margin-top:6px;line-height:1.3">drag = move x/y &middot; wheel = scale &middot; shift+wheel = z<br>ROT mode: drag = pitch/yaw &middot; wheel = scale</div>',
    ].join('');
    document.body.appendChild(el);
    el.addEventListener('click', (e) => {
      const b = e.target.closest('button'); if (!b) return;
      const act = b.dataset.act;
      const t = _api.getTuner(); if (!t) return;
      if (act && act.indexOf('sel-') === 0) t.selected = act.slice(4);
      else if (act === 'mirror') t.mirror = !t.mirror;
      else if (act === 'flip') t.flip = !t.flip;
      else if (act === 'rot') t.rotMode = !t.rotMode;
      else if (act === 'reset') {
        // Replace the tuner whole (keeps showroom's reference in sync)
        _api.setTuner(JSON.parse(JSON.stringify(_api.getDefaults())));
        _api.applyToAnchors();
      }
      _api.save();
      _updateTunerHud();
    });
    _tunerHud = el;
    return el;
  }

  function _updateTunerHud() {
    if (!_tunerHud) return;
    const t = _api.getTuner();
    if (!t) return;
    const ro = _tunerHud.querySelector('#sr-tu-readout');
    const f  = (n) => (Math.round(n*1000)/1000).toFixed(3);
    const fa = (n) => (Math.round(n*10)/10).toFixed(1);
    const sel = t.selected;
    const row = (k) => {
      const r = t[k];
      return (sel===k?'>':' ')+(k+'  ').slice(0,3)+
        ' x='+f(r.x)+' y='+f(r.y)+' z='+f(r.z)+
        ' s='+f(r.scale)+' p='+fa(r.pitch||0)+' yw='+fa(r.yaw||0);
    };
    const thr = _api.getThr();
    const hz = (thr && thr.hullBackZ != null) ? thr.hullBackZ : 0;
    ro.textContent = row('L')+'\n'+row('R')+'\n'+row('mL')+'\n'+row('mR')+
      '\nmir='+(t.mirror?'ON ':'off')+' flp='+(t.flip?'ON':'off')+
      ' rot='+(t.rotMode?'ON':'off')+' hz='+f(hz);
    _tunerHud.querySelectorAll('button').forEach(b => {
      const a = b.dataset.act;
      let on = false;
      if (a && a.indexOf('sel-') === 0) on = sel === a.slice(4);
      else if (a==='mirror') on = t.mirror;
      else if (a==='flip')   on = t.flip;
      else if (a==='rot')    on = t.rotMode;
      b.style.background = on ? '#3af' : (a==='reset' ? '#411' : '#114');
      b.style.color      = on ? '#001' : (a==='reset' ? '#fcc' : '#9cf');
    });
  }

  // ── Drag math ──────────────────────────────────────────────────────
  // Convert a screen-pixel delta to a world-space delta at the anchor's
  // depth, then bake into the anchor's parent (titleShipModel) local space.
  function _screenDeltaToLocal(dxPx, dyPx, sel) {
    _ensureScratch();
    const thr = _api.getThr();
    if (!thr || !thr.anchors) return null;
    const canvas = document.getElementById('title-ship-canvas');
    const cam = _api.getTitleCamera();
    if (!canvas || !cam) return null;
    const rect = canvas.getBoundingClientRect();
    const a = thr.anchors[sel];
    if (!a) return null;
    a.getWorldPosition(_v1);
    const ndc = _v1.clone().project(cam);
    const ndx = ndc.x + (2 * dxPx / rect.width);
    const ndy = ndc.y - (2 * dyPx / rect.height);
    _v2.set(ndx, ndy, ndc.z).unproject(cam);
    const parent = a.parent;
    if (!parent) return null;
    parent.updateMatrixWorld(true);
    const wOld = _v1.clone();
    const wNew = _v2.clone();
    parent.worldToLocal(wOld);
    parent.worldToLocal(wNew);
    return { dx: wNew.x - wOld.x, dy: wNew.y - wOld.y };
  }

  function _applyDeltaToTuner(dx, dy, dz) {
    const t = _api.getTuner(); if (!t) return;
    const sel = t.selected;
    const r = t[sel]; if (!r) return;
    r.x += dx; r.y += dy; r.z += (dz||0);
    if (t.mirror) {
      const other = t[_MIRROR_PAIR[sel]];
      if (other) { other.x = -r.x; other.y = r.y; other.z = r.z; }
    }
  }

  function _applyScaleToTuner(mul) {
    const t = _api.getTuner(); if (!t) return;
    const sel = t.selected;
    const r = t[sel]; if (!r) return;
    r.scale = Math.max(0.05, Math.min(8.0, r.scale * mul));
    if (t.mirror) {
      const other = t[_MIRROR_PAIR[sel]];
      if (other) other.scale = r.scale;
    }
  }

  // Rotate-mode delta: pixel-y → pitch (deg), pixel-x → yaw (deg). Mirrored
  // partner gets MIRRORED yaw (sign-flipped) so a 'pinch outward' affects both
  // sides symmetrically; pitch stays the same on both.
  function _applyRotDeltaToTuner(dxPx, dyPx) {
    const t = _api.getTuner(); if (!t) return;
    const sel = t.selected;
    const r = t[sel]; if (!r) return;
    const SENS = 0.25; // deg per pixel
    r.pitch = (r.pitch || 0) + dyPx * SENS;
    r.yaw   = (r.yaw   || 0) + dxPx * SENS;
    r.pitch = Math.max(-90, Math.min(90, r.pitch));
    r.yaw   = Math.max(-90, Math.min(90, r.yaw));
    if (t.mirror) {
      const other = t[_MIRROR_PAIR[sel]];
      if (other) { other.pitch = r.pitch; other.yaw = -r.yaw; }
    }
  }

  function _onMouseDown(e) {
    if (!_api.isOpen()) return;
    if (e.target.closest('#sr-tuner-hud')) return;
    if (e.target.closest('#sr-fx-hud')) return;
    if (e.target.closest('.sr-panel')) return;
    if (e.button !== 0) return;
    _tunerDragging = true;
    e.preventDefault();
  }
  function _onMouseMove(e) {
    if (!_tunerDragging || !_api.isOpen()) return;
    const t = _api.getTuner(); if (!t) return;
    const dx = e.movementX || 0, dy = e.movementY || 0;
    if (t.rotMode) {
      _applyRotDeltaToTuner(dx, dy);
    } else {
      const d = _screenDeltaToLocal(dx, dy, t.selected);
      if (!d) return;
      _applyDeltaToTuner(d.dx, d.dy, 0);
    }
    _api.applyToAnchors();
    _updateTunerHud();
  }
  function _onMouseUp() {
    if (_tunerDragging) {
      _tunerDragging = false;
      _api.save();
    }
  }
  function _onWheel(e) {
    if (!_api.isOpen()) return;
    if (e.target.closest('.sr-panel')) return;
    if (e.target.closest('#sr-tuner-hud')) return;
    if (e.target.closest('#sr-fx-hud')) return;
    e.preventDefault();
    if (e.shiftKey) {
      _applyDeltaToTuner(0, 0, -e.deltaY * 0.002);
    } else {
      _applyScaleToTuner(e.deltaY < 0 ? 1.06 : 1/1.06);
    }
    _api.applyToAnchors();
    _updateTunerHud();
    _api.save();
  }

  function _wireGlobalsOnce() {
    if (_tunerWired) return;
    _tunerWired = true;
    window.addEventListener('mousedown', _onMouseDown, { passive: false });
    window.addEventListener('mousemove', _onMouseMove);
    window.addEventListener('mouseup',   _onMouseUp);
    window.addEventListener('wheel',     _onWheel,     { passive: false });
  }

  function showTuner(show) {
    if (show) {
      _ensureTunerHud();
      _tunerHud.style.display = 'block';
      _wireGlobalsOnce();
      _updateTunerHud();
    } else if (_tunerHud) {
      _tunerHud.style.display = 'none';
    }
  }

  // ── FX HUD ─────────────────────────────────────────────────────────
  function _ensureFxHud() {
    if (_fxHud) return _fxHud;
    const el = document.createElement('div');
    el.id = 'sr-fx-hud';
    el.style.cssText = [
      'position:fixed','top:8px','left:8px','z-index:99998',
      'transform:translateY(260px)', // sits below the tuner HUD
      'font:12px/1.35 ui-monospace,Menlo,monospace','color:#cef',
      'background:rgba(0,12,24,0.82)','border:1px solid #3af','padding:8px 10px',
      'border-radius:6px','user-select:none','pointer-events:auto',
      'min-width:220px','box-shadow:0 0 12px rgba(60,180,255,0.25)'
    ].join(';');
    let rows = '<div style="font-weight:700;color:#7df;margin-bottom:6px;letter-spacing:1px;display:flex;justify-content:space-between;align-items:center">FX <button data-fx-act="reset" style="background:#411;color:#fcc;border:1px solid #f55;padding:2px 6px;border-radius:3px;cursor:pointer;font-size:10px">RST</button></div>';
    for (let i = 0; i < _FX_DEFS.length; i++) {
      const d = _FX_DEFS[i];
      rows += '<div style="display:flex;align-items:center;gap:6px;margin-top:3px">'+
        '<div style="flex:0 0 96px;font-size:10px;color:#9cf">'+d.lbl+'</div>'+
        '<input type="range" data-fx-key="'+d.key+'" min="'+d.min+'" max="'+d.max+'" step="'+d.step+'" style="flex:1;accent-color:#3af">'+
        '<div data-fx-val="'+d.key+'" style="flex:0 0 40px;font-size:10px;text-align:right;color:#cef"></div>'+
      '</div>';
    }
    el.innerHTML = rows;
    document.body.appendChild(el);
    el.addEventListener('input', (e) => {
      const inp = e.target.closest('input[type=range]'); if (!inp) return;
      const k = inp.dataset.fxKey;
      const v = parseFloat(inp.value);
      const t = _api.getTuner();
      if (t && t.fx && Number.isFinite(v)) {
        t.fx[k] = v;
        const out = el.querySelector('[data-fx-val="'+k+'"]');
        if (out) out.textContent = (Math.round(v*100)/100).toFixed(2);
      }
    });
    el.addEventListener('change', () => { _api.save(); });
    el.addEventListener('click', (e) => {
      const b = e.target.closest('[data-fx-act="reset"]'); if (!b) return;
      const t = _api.getTuner(); if (!t) return;
      t.fx = JSON.parse(JSON.stringify(_api.getDefaults().fx));
      _api.save();
      _syncFxHud();
    });
    _fxHud = el;
    _syncFxHud();
    return el;
  }

  function _syncFxHud() {
    if (!_fxHud) return;
    const t = _api.getTuner();
    if (!t || !t.fx) return;
    for (let i = 0; i < _FX_DEFS.length; i++) {
      const k = _FX_DEFS[i].key;
      const inp = _fxHud.querySelector('input[data-fx-key="'+k+'"]');
      const out = _fxHud.querySelector('[data-fx-val="'+k+'"]');
      const v = t.fx[k];
      if (inp) inp.value = v;
      if (out) out.textContent = (Math.round(v*100)/100).toFixed(2);
    }
  }

  function showFx(show) {
    if (show) {
      _ensureFxHud();
      _fxHud.style.display = 'block';
      _syncFxHud();
    } else if (_fxHud) {
      _fxHud.style.display = 'none';
    }
  }

  // ── Public ─────────────────────────────────────────────────────────
  function init(api) { _api = api; }

  window.TunerHud = {
    init: init,
    showTuner: showTuner,
    showFx: showFx,
    updateTuner: _updateTunerHud,
  };
})();
//  SHOP SYSTEM
// ═══════════════════════════════════════════════════

function toggleLeaderboard() {
  const overlay = document.getElementById('lb-overlay');
  if (overlay) overlay.classList.toggle('hidden');
}
window.toggleLeaderboard = toggleLeaderboard;

// ── Shop affordability check (used by HUD notification dot) ──
function _canAffordAnyShopItem() {
  const coins = loadCoinWallet();
  const owned = JSON.parse(localStorage.getItem('jh_owned_skins') || '["RUNNER"]');
  if (SHIP_SKINS.some(s => s.price > 0 && !owned.includes(s.name) && coins >= s.price)) return true;
  return Object.entries(POWERUP_UPGRADES).some(([id, up]) => {
    const tier = loadUpgradeTier(id);
    const cost = getUpgradeCost(id, tier);
    return tier < (up.maxTier || 5) && cost !== null && coins >= cost;
  });
}

function _showShopArrow() { /* removed */ }
function _hideShopArrow() { /* removed */ }

function openShop() {
  initAudio();
  playTitleTap();
  _hideShopArrow();
  state._shopOpened = true;
  updateNotificationDots();
  const overlay = document.getElementById('shop-overlay');
  if (!overlay) return;
  overlay.classList.remove('hidden');
  overlay.classList.add('shop-open');
  document.getElementById('shop-coin-count').textContent = _totalCoins;
  closeShopDetail();
  renderPowerupCards();
  updateNotificationDots();
  _renderShopHandlingBar();
}
window.openShop = openShop;

function _renderShopHandlingBar() {
  const bar = document.getElementById('shop-handling-bar');
  if (!bar) return;
  const level = loadPlayerLevel();
  // Find current and next tier
  let currentTier = HANDLING_TIERS[0];
  let nextTier = null;
  for (let i = 0; i < HANDLING_TIERS.length; i++) {
    if (level >= HANDLING_TIERS[i].level) currentTier = HANDLING_TIERS[i];
    else { nextTier = HANDLING_TIERS[i]; break; }
  }
  const tierLabel = currentTier.label || 'Stock';
  const handlingPct = Math.round((1 - currentTier.drift) * 100);
  // Progress toward next tier
  let fillPct = 100;
  let nextText = 'MAX HANDLING';
  if (nextTier) {
    const prevLevel = currentTier.level;
    const needed = nextTier.level - prevLevel;
    const progress = level - prevLevel;
    fillPct = Math.min(100, Math.round((progress / needed) * 100));
    nextText = 'Next: ' + nextTier.label + ' (Lv ' + nextTier.level + ')';
  }
  bar.innerHTML =
    '<div class="shop-handling-label">SHIP HANDLING</div>' +
    '<div class="shop-handling-tier">' + tierLabel + ' \u2022 ' + handlingPct + '% Control</div>' +
    '<div class="shop-handling-track"><div class="shop-handling-fill" style="width:' + fillPct + '%"></div></div>' +
    '<div class="shop-handling-next">' + nextText + '</div>';
}

function closeShop() {
  playTitleTap();
  const overlay = document.getElementById('shop-overlay');
  if (!overlay) return;
  overlay.classList.remove('shop-open');
  overlay.classList.add('hidden');
}
window.closeShop = closeShop;

function switchShopTab(tab) {
  document.querySelectorAll('.shop-tab').forEach(t => {
    t.classList.toggle('active', t.dataset.tab === tab);
  });
  document.getElementById('shop-tab-powerups').classList.toggle('hidden', tab !== 'powerups');
  document.getElementById('shop-detail').classList.add('hidden');
}

// Tab click handlers
document.addEventListener('DOMContentLoaded', () => {
  document.querySelectorAll('.shop-tab').forEach(tab => {
    _tapBind(tab, () => switchShopTab(tab.dataset.tab));
  });

});

function renderPowerupCards() {
  const container = document.getElementById('shop-powerup-cards');
  if (!container) return;
  container.innerHTML = '';
  const playerLevel = loadPlayerLevel();
  const isNew = hasNewShopUnlock();
  Object.entries(POWERUP_UPGRADES).forEach(([id, up]) => {
    const tier = loadUpgradeTier(id);
    const cost = getUpgradeCost(id, tier);
    // Lock by level gate OR ladder unlock state
    const levelLocked = up.levelGate && playerLevel < up.levelGate;
    const ladderLocked = (id !== 'shield' && id !== 'coinvalue') && !isPowerupUnlocked(id);
    const locked = levelLocked || ladderLocked;
    const mt = up.maxTier || 5;
    const maxed = tier >= mt;
    const canAfford = cost !== null && _totalCoins >= cost;
    // Check if this was just unlocked (show NEW badge)
    const justUnlocked = isNew && !locked && id !== 'shield';

    const card = document.createElement('div');
    card.className = 'shop-card' + (canAfford && !maxed && !locked ? ' affordable' : '') + (locked ? ' locked' : '') + (justUnlocked ? ' new-unlock' : '');
    card.style.borderColor = up.color;

    let lockLabel = '';
    if (ladderLocked) lockLabel = `<div class="shop-card-lock">\uD83D\uDD12 MISSIONS</div>`;
    else if (levelLocked) lockLabel = `<div class="shop-card-lock">LV ${up.levelGate}</div>`;

    card.innerHTML = `
      <div class="shop-card-icon" style="color:${up.color}">${up.icon}</div>
      <div class="shop-card-name">${up.name}</div>
      <div class="shop-card-pips">${renderPips(tier, up.color)}</div>
      <div class="shop-card-desc">${up.tiers[tier - 1]?.desc || 'MAX'}</div>
      ${locked ? lockLabel :
        maxed ? '<div class="shop-card-maxed">MAXED</div>' :
        `<div class="shop-card-cost">${cost !== null ? '\u2B21 ' + cost : ''}</div>`}
      ${justUnlocked ? '<div class="shop-new-badge">NEW</div>' : ''}
    `;
    if (!locked && !maxed) {
      _tapBind(card, () => {
        // Clear NEW flag when they tap a newly unlocked card
        if (justUnlocked) window._LS.removeItem('jetslide_shop_new');
        updateNotificationDots();
        openShopDetail(id);
      });
    }
    container.appendChild(card);
  });
}

function renderPips(tier, color) {
  let html = '';
  for (let i = 1; i <= 5; i++) {
    html += `<span class="shop-pip${i <= tier ? ' filled' : ''}" style="${i <= tier ? 'background:' + color : ''}"></span>`;
  }
  return html;
}

function openShopDetail(id) {
  const detail = document.getElementById('shop-detail');
  const content = document.getElementById('shop-detail-content');
  if (!detail || !content) return;

  // Hide cards and handling bar, show detail
  document.getElementById('shop-tab-powerups').classList.add('hidden');
  document.getElementById('shop-handling-bar').classList.add('hidden');
  detail.classList.remove('hidden');

  const isPowerup = !!POWERUP_UPGRADES[id];
  const up = isPowerup ? POWERUP_UPGRADES[id] : STAT_UPGRADES[id];
  const tier = loadUpgradeTier(id);
  const cost = getUpgradeCost(id, tier);
  const maxed = tier >= (up.maxTier || 5);
  const canAfford = cost !== null && _totalCoins >= cost;
  const color = isPowerup ? up.color : '#0af';

  let tiersHTML = '';
  const tiers = isPowerup ? up.tiers : up.tiers.map((t, i) => ({ desc: t }));
  for (let i = 0; i < 5; i++) {
    const desc = isPowerup ? tiers[i].desc : up.tiers[i];
    const active = i < tier;
    const next = i === tier;
    tiersHTML += `<div class="shop-detail-tier${active ? ' active' : ''}${next ? ' next' : ''}" style="${active ? 'border-color:' + color : ''}">
      <span class="shop-detail-tier-num">T${i + 1}</span>
      <span class="shop-detail-tier-desc">${desc}</span>
      ${isPowerup ? `<span class="shop-detail-tier-cost">${i === 0 ? 'FREE' : '<img src="assets/images/single-coin-icon.png" style="width:14px;height:14px;object-fit:contain;vertical-align:middle;"> ' + UPGRADE_COSTS[i]}</span>` :
        `<span class="shop-detail-tier-cost">${'<img src="assets/images/single-coin-icon.png" style="width:14px;height:14px;object-fit:contain;vertical-align:middle;"> ' + up.costs[i]}</span>`}
    </div>`;
  }

  content.innerHTML = `
    <div class="shop-detail-header">
      ${isPowerup ? `<span class="shop-detail-icon" style="color:${color}">${up.icon}</span>` : ''}
      <span class="shop-detail-name" style="color:${color}">${up.name}</span>
    </div>
    <div class="shop-detail-pips">${renderPips(tier, color)}</div>
    <div class="shop-detail-tiers">${tiersHTML}</div>
    ${maxed ? '<div class="shop-detail-maxed">FULLY UPGRADED</div>' :
      `<button class="btn-space btn-upgrade shop-upgrade-btn${canAfford ? '' : ' disabled'}" id="shop-buy-btn" style="--up-color:${color}">
        UPGRADE <img src="assets/images/single-coin-icon.png" style="width:14px;height:14px;object-fit:contain;vertical-align:middle;"> ${cost}
      </button>`}
  `;

  if (!maxed) {
    const buyBtn = document.getElementById('shop-buy-btn');
    if (buyBtn) {
      _tapBind(buyBtn, () => {
        if (purchaseUpgrade(id)) {
          // Animate purchase
          buyBtn.classList.add('shop-purchase-anim');
          document.getElementById('shop-coin-count').textContent = _totalCoins;
          // SFX
          playShopPurchase();
          // Re-render detail after animation
          setTimeout(() => {
            openShopDetail(id);
            renderPowerupCards();
          }, 400);
        }
      });
    }
  }
}
window.openShopDetail = openShopDetail;

function closeShopDetail() {
  playTitleTap();
  const detail = document.getElementById('shop-detail');
  if (detail) detail.classList.add('hidden');
  const tabs = document.querySelectorAll('.shop-tabs')[0];
  if (tabs) tabs.classList.remove('hidden');
  // Show the powerups content and handling bar
  const puTab = document.getElementById('shop-tab-powerups');
  if (puTab) puTab.classList.remove('hidden');
  const handlingBar = document.getElementById('shop-handling-bar');
  if (handlingBar) handlingBar.classList.remove('hidden');
}
window.closeShopDetail = closeShopDetail;

function navigateToSkin(idx) {
  playTitleTap();
  skinViewerIdx = idx;
  // Always apply visually so player sees the 3D ship change
  applySkin(idx);
  // Update title ship preview clone too
  applyTitleSkin(idx);

  const data = loadSkinData();
  // If unlocked (or admin), save as selected
  if (_skinAdminMode || isSkinUnlocked(idx)) {
    data.selected = idx;
    saveSkinData(data);
  }
  updateSkinViewerDisplay();
}

function updateSkinViewerDisplay() {
  const labelEl = document.getElementById('skin-viewer-label');
  if (!labelEl) return;
  const data = loadSkinData();
  const skin = SHIP_SKINS[skinViewerIdx];
  const isSelected = data.selected === skinViewerIdx;
  const isUnlocked = _skinAdminMode || isSkinUnlocked(skinViewerIdx);
  const requiredLevel = SKIN_LEVEL_UNLOCKS[skinViewerIdx] || 1;

  // Label: skin name + checkmark/USE/lock inline
  if (skinViewerIdx === 0 || isUnlocked) {
    if (isSelected) {
      labelEl.innerHTML = skin.name + ' <span class="skin-check">&check;</span>';
    } else {
      labelEl.innerHTML = skin.name + ' <button class="skin-use-btn" onclick="selectSkin(' + skinViewerIdx + ')">USE</button>';
    }
    labelEl.classList.remove('skin-locked');
  } else {
    labelEl.innerHTML = skin.name + ' <span class="skin-lock-tag">\u{1F512} LV' + requiredLevel + '</span>';
    labelEl.classList.add('skin-locked');
  }

  // Clear the old action row (no longer used)
  const actionEl = document.getElementById('skin-viewer-action');
  if (actionEl) actionEl.innerHTML = '';
}

function selectSkin(idx) {
  const data = loadSkinData();
  data.selected = idx;
  saveSkinData(data);
  applySkin(idx);
  applyTitleSkin(idx);
  updateSkinViewerDisplay();
}

function buySkin(idx) {
  // Legacy — no longer used for purchasing. Skins are level-gated.
  selectSkin(idx);
}

// Make these available from onclick attributes
window.selectSkin = selectSkin;
window.buySkin = buySkin;

function applyPowerup(typeIdx) {
  hapticTap(); // powerup pickup
  state.sessionPowerups++;
  const def = POWERUP_TYPES[typeIdx];
  showBanner(def.label, 'mission', 1500);
  if (def.id === 'shield') state.sessionShields++;
  if (def.id === 'laser') state.sessionLasers++;
  if (def.id === 'invincible') state.sessionInvincibles++;
  playPickup(typeIdx); // pickup smash for ALL powerups; shield also layers shield-activate-sfx below
  addCrashFlash(def.color);

  switch (def.id) {
    case 'shield': {
      const tier = loadUpgradeTier('shield');
      state.shieldActive = true;
      // T1=10s, T2=15s, T3+=permanent (0 = no timer)
      state.shieldDuration = (tier >= 3) ? 0 : (tier >= 2) ? 15 : 10;
      state.shieldTimer = state.shieldDuration;
      // T1-T3=1hit, T4=stacks to 2, T5=stacks to 3
      const maxHits = (tier >= 5) ? 3 : (tier >= 4) ? 2 : 1;
      if (state.shieldActive && state.shieldHitPoints > 0 && maxHits > 1) {
        // Stacking: add a hit point up to max
        state.shieldHitPoints = Math.min(maxHits, state.shieldHitPoints + 1);
      } else {
        state.shieldHitPoints = 1;
      }
      // Color based on tier (changes at T3+ permanent)
      // T1-T2=cyan, T3=green, T4=purple, T5=orange
      const shieldTierColors = [0x26aeff, 0x26aeff, 0x00f0cc, 0x00f0cc, 0x00f0cc];
      const sc = shieldTierColors[tier - 1] || 0x00f0ff;
      shieldMat.uniforms.uColor.value.setHex(sc);
      shieldMat.uniforms.uNoiseEdgeColor.value.setHex(sc);
      shieldLight.color.setHex(sc);
      state.shieldBuildT = 0;
      state._shieldBreakT = null;
      shieldMesh.visible = false;
      shieldWire.visible = false;
      shieldLight.intensity = 0;
      const _shActSfx = document.getElementById('shield-activate-sfx'); if (_shActSfx) { _shActSfx.currentTime = 0; _shActSfx.volume = 0.18; _shActSfx.play().catch(()=>{}); }
      break;
    }
    case 'laser': {
      const tier = loadUpgradeTier('laser');
      state.laserActive = true;
      state.laserTier = tier;
      // Base duration 4s, +25% per tier above 1
      const baseDur = 4;
      state.laserTimer = baseDur * (1 + (tier - 1) * 0.25);
      // Laser color evolves: red → orange → yellow → white-hot
      const laserColors = [0xff2200, 0xff5500, 0xff8800, 0xffbb00, 0xffee44];
      state.laserColor = laserColors[tier - 1];
      if (tier <= 3) {
        // T1-T3: bolt machine gun mode
        laserPivot.visible = false;
        state.laserBoltTimer = 0;
        // Laser MG SFX: retrigger the <audio> element at MG cadence.
        // Element-based path (not buffer source) for iOS reliability — buffer
        // sources require a fully-unlocked AudioContext, which can be silent
        // on the first laser pickup of a session. Element clones work after
        // any user gesture, including touch.
        const _lsfx = document.getElementById('laser-beam-sfx');
        if (_lsfx && !state.muted) {
          _lsfx.loop = false;
          _lsfx.volume = 0.2;
          try { _lsfx.currentTime = 0; _lsfx.play().catch(()=>{}); } catch(_) {}
          const _retriggerMs = 120; // ~8 shots/sec
          if (state._laserSfxIv) { clearInterval(state._laserSfxIv); state._laserSfxIv = null; }
          // Cancel any prior stop-timeout from an earlier pickup so it can't fire
          // mid-second-laser and kill the new interval before its time.
          if (state._laserSfxStopTo) { clearTimeout(state._laserSfxStopTo); state._laserSfxStopTo = null; }
          state._laserSfxIv = setInterval(() => {
            try { _lsfx.currentTime = 0; _lsfx.play().catch(()=>{}); } catch(_) {}
          }, _retriggerMs);
          // Stop retriggering when laser ends, but DON'T cut the in-flight shot.
          // It plays out naturally to its end (final tail rings out).
          state._laserSfxStopTo = setTimeout(() => {
            state._laserSfxStopTo = null;
            if (state._laserSfxIv) { clearInterval(state._laserSfxIv); state._laserSfxIv = null; }
          }, state.laserTimer * 1000);
        }
        // T1/T2: 2 lanes, narrow. T3: 4 lanes, wider spread
        // If scene tuner (T) is open, let slider values stay in control
        if (!window._sceneTunerOpen) {
          const _lc = SHIP_SKINS[activeSkinIdx] && SHIP_SKINS[activeSkinIdx].laserConfig;
          if (_lc) {
            state._laserBoltLanes  = _lc.lanes;
            state._laserBoltSpread = _lc.spread;
            state._laserBoltYOff   = _lc.yOff;
            state._laserBoltZOff   = _lc.zOff;
            state._laserBoltLen    = _lc.len;
            state._laserBoltGlow   = _lc.glowLen;
            state.laserFireRate    = _lc.fireRate;
          } else {
            state._laserBoltLanes  = tier <= 2 ? 2 : 4;
            state._laserBoltSpread = tier <= 2 ? 0.35 : 0.50;
            state._laserBoltYOff   = tier <= 2 ? 0 : -0.25;
            state._laserBoltZOff   = -2;
            state._laserBoltLen    = tier <= 2 ? 2.0 : 1.9;
            state._laserBoltGlow   = tier <= 2 ? 2.5 : 2.7;
            state.laserFireRate    = _lbFireRate;
          }
        }
      } else if (tier === 4) {
        // T4: unibeam
        state.laserBoltTimer = 0;
        state._laserScanActive = false;
        const _ubsfx = document.getElementById('unibeam-sfx');
        if (_ubsfx && !state.muted) { _ubsfx.currentTime = 0; _ubsfx.volume = 0.6; _ubsfx.loop = true; _ubsfx.play().catch(()=>{}); }
        setTimeout(() => { const s = document.getElementById('unibeam-sfx'); if (s) { s.loop = false; s.pause(); s.currentTime = 0; } }, state.laserTimer * 1000);
      } else {
        // T5: scanning unibeam
        state._laserScanAngle  = 0;
        state._laserScanDir    = 1;
        state._laserScanActive = true;
        state.laserBoltTimer   = 0;
        const _ubsfx = document.getElementById('unibeam-sfx');
        if (_ubsfx && !state.muted) { _ubsfx.currentTime = 0; _ubsfx.volume = 0.6; _ubsfx.loop = true; _ubsfx.play().catch(()=>{}); }
        setTimeout(() => { const s = document.getElementById('unibeam-sfx'); if (s) { s.loop = false; s.pause(); s.currentTime = 0; } }, state.laserTimer * 1000);
      }
      break;
    }
    case 'invincible': {
      const tier = loadUpgradeTier('invincible');
      state.shieldActive = true;
      state.invincibleTimer = [5, 6, 7.5, 9, 10][tier - 1];
      state.invincibleGrace = (tier >= 5) ? 3.0 : 2.0;
      state.invincibleSpeedActive = true;
      shieldMesh.visible = false; shieldWire.visible = false;
      shieldMat.uniforms.uReveal.value = 1.0;
      shieldWireMat.opacity = 0;
      shieldLight.intensity = 0;
      // Force-field loop: starts at 0 during speed phase
      const _invSfx = document.getElementById('invincible-loop-sfx');
      if (_invSfx && !state.muted) {
        try { _invSfx.currentTime = 0; _invSfx.loop = true; _invSfx.volume = 0.45; _invSfx.play().catch(()=>{}); } catch(_) {}
      }
      break;
    }

    case 'magnet': {
      const tier = loadUpgradeTier('magnet');
      state.magnetActive = true;
      state.magnetTimer = [4, 5, 6, 7, 8][tier - 1];
      state.magnetRadius = [18, 21, 23, 27, 31][tier - 1];
      state.magnetPullsPowerups = (tier >= 5);
      magnetRing.visible = true; magnetRing2.visible = true;
      _startMagnetWhir();
      break;
    }
  }
  updatePowerupTray();
}

function updateMultiplierHUD() {
  const el = document.getElementById('hud-multiplier');
  if (state.multiplier > 1) {
    el.textContent = `✕${state.multiplier}`;
    el.classList.remove('hidden');
  } else {
    el.classList.add('hidden');
  }
}

function updatePowerupTray() {
  const tray = document.getElementById('powerup-tray');
  tray.innerHTML = '';

  // Shield: show as dots at bottom center (separate from tray)
  let shieldDots = document.getElementById('shield-dots');
  if (!shieldDots) {
    shieldDots = document.createElement('div');
    shieldDots.id = 'shield-dots';
    shieldDots.style.cssText = 'position:fixed;bottom:12px;left:50%;transform:translateX(-50%);display:flex;gap:6px;z-index:60;pointer-events:none;';
    document.body.appendChild(shieldDots);
  }
  if (state.shieldActive && state.invincibleTimer <= 0) {
    const hp = state.shieldHitPoints || 1;
    shieldDots.innerHTML = '';
    for (let i = 0; i < hp; i++) {
      const dot = document.createElement('div');
      dot.style.cssText = 'width:8px;height:8px;border-radius:50%;background:#00f0ff;box-shadow:0 0 6px #00f0ff;opacity:0.8;';
      shieldDots.appendChild(dot);
    }
    shieldDots.style.display = 'flex';
  } else {
    shieldDots.style.display = 'none';
  }

  // Timed powerups: just countdown bars, no icons
  const slots = [];
  if (state.laserActive)        slots.push({ t: state.laserTimer, max: state.laserTimer > 0 ? [4,5,6,7,8][Math.max(0,(state.laserTier||1)-1)] : 8, color: state.laserColor || 0xff2200 });
  if (state.invincibleTimer > 0) slots.push({ t: state.invincibleTimer, max: [5,6,7.5,9,10][(loadUpgradeTier('invincible')||1)-1], color: 0xffcc00 });
  if (state.magnetActive)       slots.push({ t: state.magnetTimer, max: [4,5,6,7,8][(loadUpgradeTier('magnet')||1)-1], color: 0x44ff88 });
  if (state.shieldActive && state.shieldDuration > 0) slots.push({ t: state.shieldTimer, max: state.shieldDuration, color: 0x26aeff });

  slots.forEach(s => {
    const slot = document.createElement('div');
    slot.className = 'powerup-slot';
    const pct = Math.min(100, (s.t / s.max) * 100);
    const hex = '#' + s.color.toString(16).padStart(6, '0');
    slot.innerHTML = `<div class="powerup-bar-track"><div class="powerup-bar-fill" style="width:${pct}%;background:${hex}"></div></div>`;
    tray.appendChild(slot);
  });
}

// ═══════════════════════════════════════════════════
//  CRASH FLASH
// ═══════════════════════════════════════════════════
function addCrashFlash(hexColor) {
  const el = document.createElement('div');
  el.className = 'crash-flash';
  if (hexColor) el.style.background = `radial-gradient(ellipse at center, rgba(${(hexColor>>16)&255},${(hexColor>>8)&255},${hexColor&255},0.6), transparent)`;
  document.body.appendChild(el);
  el.addEventListener('animationend', () => el.remove());
}

// ═══════════════════════════════════════════════════
//  INPUT
// ═══════════════════════════════════════════════════
const keys = {};
// Touch control state — fed by on-screen buttons
const touch = { left: false, right: false, rollUp: false, rollDown: false, rollToggle: false };
function setPauseOverlay(visible) {
  const el = document.getElementById('pause-overlay');
  if (!el) return;
  if (visible) {
    el.classList.remove('hidden');
    document.getElementById('hud').classList.add('hidden');
  } else {
    el.classList.add('hidden');
    if (state.phase === 'playing') document.getElementById('hud').classList.remove('hidden');
  }
}
// Expose for inline onclick on pause buttons
window.togglePause    = () => { if (state.phase === 'playing' || state.phase === 'paused') togglePause(); };
window.returnToTitle  = returnToTitle;
window.playResumeSound = () => playResumeSound();
window.playExitSound   = () => playExitSound();
// Helper: which music track should be playing right now in-game?
function currentGameTrack() {
  // Death Run: track selection driven by per-stage musicTrack field.
  // The latest musicTrack set by any stage at or before the current index wins.
  if (state.isDeathRun) {
    if (typeof DR_SEQUENCE !== 'undefined') {
      const _idx = state.seqStageIdx || 0;
      let _t = 'bg';
      for (let i = 0; i <= _idx && i < DR_SEQUENCE.length; i++) {
        if (DR_SEQUENCE[i].musicTrack) _t = DR_SEQUENCE[i].musicTrack;
      }
      return _t;
    }
    return 'bg';
  }
  // Title only plays after the L5 corridor completes (ending/sail-out phase)
  if (state.currentLevelIdx === 4 && state.l5CorridorDone) return 'title';
  if (state.currentLevelIdx >= 3) return 'l4';  // L4 and all of L5 up to corridor end
  if (state.currentLevelIdx >= 2) return 'l3';
  return 'bg';
}

// (crossfadeTracks is defined earlier as a thin wrapper around musicFadeTo)

function togglePause() {
  if (state.phase === 'playing') {
    state.phase = 'paused';
    // Kill any in-flight intro text
    clearIntroTimers();
    const _introOv = document.getElementById('intro-overlay');
    if (_introOv) { fadeOutIntroOverlay(_introOv); }
    state.introActive = false;
    killThrusterSputter();
    // Pause engine SFX
    const _engP = document.getElementById('engine-start');
    const _roarP = document.getElementById('engine-roar');
    const _roarLP = document.getElementById('engine-roar-layer');
    if (_engP && !_engP.paused) _engP.pause();
    if (_roarP && !_roarP.paused) _roarP.pause();
    if (_roarLP && !_roarLP.paused) _roarLP.pause();
    stopEngineBaseline();
    if (state._argonCutIv) { clearInterval(state._argonCutIv); state._argonCutIv = null; }
    if (state._argonReplayTo) { clearTimeout(state._argonReplayTo); state._argonReplayTo = null; }
    if (state._argonSrc) { try { state._argonSrc.stop(); } catch (_) {} state._argonSrc = null; }
    state._argonPath = null;
    state._argonPlayCount = 0;
    const _argonP = document.getElementById('argon-ambient-sfx');
    if (_argonP && !_argonP.paused) { try { _argonP.pause(); _argonP.currentTime = 0; _argonP.volume = 0; } catch (_) {} }
    state._argonSteering = false;
    state._argonOpen = 0;
    _stopMagnetWhir();
    const _invP = document.getElementById('invincible-loop-sfx');
    if (_invP && !_invP.paused) _invP.pause();
    // Pause looped weapon SFX so they don't bleed through pause.
    // currentTime preserved so they pick up where they left off on resume.
    const _laserP = document.getElementById('laser-beam-sfx');
    if (_laserP && !_laserP.paused) _laserP.pause();
    if (state._laserSfxIv) { clearInterval(state._laserSfxIv); state._laserSfxIv = null; }
    if (state._laserSfxStopTo) { clearTimeout(state._laserSfxStopTo); state._laserSfxStopTo = null; }
    const _ubeamP = document.getElementById('unibeam-sfx');
    if (_ubeamP && !_ubeamP.paused) _ubeamP.pause();
    // Kill in-flight thunder rumble so it doesn't ring through pause.
    if (typeof _thunderActiveSrc !== 'undefined' && _thunderActiveSrc) {
      try { _thunderActiveSrc.stop(); } catch (_) {}
      _thunderActiveSrc = null;
    }
    if (state._lakeFadeIv) { clearInterval(state._lakeFadeIv); state._lakeFadeIv = null; }
    if (activeFadeIv) { clearInterval(activeFadeIv); activeFadeIv = null; }
    setPauseOverlay(true);
    pauseGameTrackInPlace(currentGameTrack());
    if (state._tutorialActive) _tutHideText();
  } else if (state.phase === 'paused') {
    state.phase = 'playing';
    setPauseOverlay(false);
    resumeGameTrackInPlace(currentGameTrack());
    // Resume baseline whir on unpause (smooth fade-in)
    startEngineBaseline(0.5);
    // Argon is edge-triggered — will fire on next steer input, nothing to resume
    // Resume invincible loop if active
    const _invU = document.getElementById('invincible-loop-sfx');
    if (_invU && state.invincibleTimer > 0 && !state.muted) { _invU.play().catch(()=>{}); }
    // Resume looped weapon SFX if their power-up timer is still running.
    if (state.laserActive && !state.muted) {
      const _tier = state.laserTier || 1;
      if (_tier <= 3) {
        const _laserU = document.getElementById('laser-beam-sfx');
        if (_laserU) _laserU.play().catch(()=>{});
      } else {
        const _ubeamU = document.getElementById('unibeam-sfx');
        if (_ubeamU) _ubeamU.play().catch(()=>{});
      }
    }
    if (state._tutorialActive) { const el = document.getElementById('tutorial-overlay'); if (el) el.style.opacity = '1'; }
  }
}

function returnToTitle() {
  state.phase = 'title';
  // Release the thruster color lock so the title vibe (and the title
  // thruster panel preview) can repaint the thruster color again.
  window._thrusterColorLocked = false;
  // Release transition reentry locks — a tap mid-startGame followed by
  // pause+exit can otherwise leave these stuck, blocking the next Play tap.
  // (Both flags live in 67-main-late.js but share the concat'd module scope.)
  _gameStarting = false;
  _retryPending = false;
  shipGroup.visible = true;
  _killExplosion();
  // ── Hard camera reset: prevent stale death/retry camera leaking into title ──
  _retrySweepActive = false;
  _retrySweepT = 0;
  cameraPivot.position.set(0, 2.8 + _camPivotYOffset, 9 + _camPivotZOffset);
  cameraRoll = 0;
  camera.rotation.set(0, 0, 0);
  camera.position.set(0, 0, 0);
  camera.lookAt(new THREE.Vector3(0, -2.8 + _camLookYOffset, -50 + _camLookZOffset));
  camera.fov = _baseFOV;
  camera.updateProjectionMatrix();
  if (_gameOverDelayTimer) { clearTimeout(_gameOverDelayTimer); _gameOverDelayTimer = null; }
  if (_titleFadeTimer) { clearTimeout(_titleFadeTimer); _titleFadeTimer = null; }
  if (state._lakeFadeIv) { clearInterval(state._lakeFadeIv); state._lakeFadeIv = null; }
  clearMusicTimers();
  // Show inline leaderboard on title
  const _tlb = document.getElementById('title-leaderboard');
  if (_tlb) _tlb.classList.remove('hidden');
  renderLeaderboard();
  // Clean up any tutorial overlays
  _tutDestroyOverlay();
  // Clear tutorial flag — settings/tuner overlay can route back to title
  // without going through the EXIT TUTORIAL button, leaving _tutorialActive
  // stuck true and gating the next run's spawner. (No-spawn-cones bug.)
  state._tutorialActive = false;
  // Clear any active banners
  const bc = document.getElementById('banner-container');
  if (bc) bc.innerHTML = '';
  // Reset title ship glow pulse state
  _titleGlowPhase = 0;
  for (const entry of _titleMeshMap) {
    const mat = entry.mesh.material;
    if (mat && mat.userData && mat.userData._baseEI !== undefined) {
      mat.emissiveIntensity = mat.userData._baseEI;
      delete mat.userData._baseEI;
    }
  }
  // Kill any in-flight intro text
  clearIntroTimers();
  const _introOv = document.getElementById('intro-overlay');
  if (_introOv) { fadeOutIntroOverlay(_introOv); }
  state.introActive = false;
  // Reset launch-lift state so a mid-lift exit doesn't leave the next start
  // (or the title scene's shared shipGroup) pitched/raised.
  state._introLiftActive = false;
  state._introLiftTimer = 0;
  state._introShipY = _hoverBaseY;
  shipGroup.position.x = 0;
  shipGroup.position.y = _hoverBaseY;
  // Preserve shipGroup.position.z (init'd to 3.9, never changes during gameplay).
  shipGroup.rotation.set(_shipRotXOffset, 0, 0);
  killThrusterSputter();
  // Cancel any pending retry-sweep startGame call so it can't fire after exit
  if (_retryFadeTimer) { clearTimeout(_retryFadeTimer); _retryFadeTimer = null; }
  // Dismiss head-start prompt if it was up — its 4s auto-dismiss timeout
  // would otherwise fire over the title screen.
  dismissHeadStart();
  // Clear all in-flight objects and mechanic state
  _clearAllMechanics();
  // Lightning + asteroids are pool-based and not in _clearAllMechanics; both
  // can leak past death/exit (lightning bolts freeze visible mid-strike, and
  // _updateAsteroids ticks every frame regardless of phase so rocks keep
  // falling onto the title screen). Clear them explicitly here.
  if (typeof window._clearAllLightning === 'function') window._clearAllLightning();
  if (typeof window._clearAllAsteroids === 'function') window._clearAllAsteroids();
  // Restore dirLight.intensity if a JL canyon was active when the player
  // exited (death-then-exit, or future direct exit-mid-canyon). _jlCanyonStop
  // is the only function that restores _canyonSavedDirLight, and it doesn't
  // run on death/exit — leaving the title scene with the sun's directional
  // light at 0.
  if (_canyonSavedDirLight !== null && typeof dirLight !== 'undefined' && dirLight) {
    dirLight.intensity = _canyonSavedDirLight;
    _canyonSavedDirLight = null;
  }
  // Bonus rings (opening rings) are not in _clearAllMechanics — wipe explicitly.
  _ringRemoveAll();
  // Coins, laser bolts, active powerups: startGame() resets these but exiting
  // to title and starting a new run could otherwise show stale objects flash
  // during the title fade.
  ;[...activeCoins].forEach(returnCoinToPool);
  activeCoins.length = 0;
  coinArcPending.length = 0;
  laserBolts.forEach(b => { b.visible = false; });
  activePowerups.forEach(pu => {
    pu.userData.active = false;
    pu.visible = false;
    pu.position.set(0, -9999, 0);
    pu.scale.setScalar(1);
  });
  activePowerups.length = 0;
  [..._activeForcefields].forEach(returnForcefieldToPool);
  _activeForcefields.length = 0;
  // Show title, hide everything else
  const _tEl = document.getElementById('title-screen');
  _tEl.classList.remove('hidden');
  _tEl.classList.remove('fading-out');
  document.getElementById('gameover-screen').classList.add('hidden');
  document.getElementById('reward-wheel-overlay').classList.add('hidden');
  document.getElementById('hud').classList.add('hidden');
  setPauseOverlay(false);
  document.getElementById('touch-controls').classList.add('hidden');
  document.getElementById('settings-btn').style.display = ''; // show gear on title/gameover
  document.getElementById('lb-icon-btn').style.display = ''; // show trophy on title
  document.getElementById('lb-overlay').classList.add('hidden'); // close leaderboard overlay
  // Stop all gameplay music, reset to start, clear crossfade timer, restart title music
  if (activeFadeIv) { clearInterval(activeFadeIv); activeFadeIv = null; }
  ['bg', 'l3', 'l4'].forEach(k => {
    const el = allTracks()[k];
    if (!el) return;
    el.pause();
    el.currentTime = 0;
    setTrackVol(k, 0);
  });
  // Stop lake ambience on return to title
  if (lakeMusic) { lakeMusic.pause(); lakeMusic.currentTime = 0; setTrackVol('lake', 0); }
  // Stop engine SFX
  const _engR = document.getElementById('engine-start');
  const _roarR = document.getElementById('engine-roar');
  const _roarLR = document.getElementById('engine-roar-layer');
  if (_engR) { _engR.pause(); _engR.currentTime = 0; }
  if (_roarR) { _roarR.pause(); _roarR.currentTime = 0; }
  if (_roarLR) { _roarLR.pause(); _roarLR.currentTime = 0; }
  stopEngineBaseline({ reset: true });
  if (state._argonCutIv) { clearInterval(state._argonCutIv); state._argonCutIv = null; }
  if (state._argonReplayTo) { clearTimeout(state._argonReplayTo); state._argonReplayTo = null; }
  if (state._argonSrc) { try { state._argonSrc.stop(); } catch (_) {} state._argonSrc = null; }
  state._argonPath = null;
  state._argonPlayCount = 0;
  const _argonR = document.getElementById('argon-ambient-sfx');
  if (_argonR) { try { _argonR.pause(); _argonR.currentTime = 0; _argonR.volume = 0; } catch (_) {} }
  state._argonSteering = false;
  state._argonOpen = 0;
  _stopMagnetWhir();
  const _invR = document.getElementById('invincible-loop-sfx');
  if (_invR) { _invR.pause(); _invR.currentTime = 0; _invR.loop = false; }
  // Stop looped weapon SFX on return to title.
  const _laserR = document.getElementById('laser-beam-sfx');
  if (_laserR) { _laserR.loop = false; _laserR.pause(); _laserR.currentTime = 0; }
  if (state._laserSfxIv) { clearInterval(state._laserSfxIv); state._laserSfxIv = null; }
  if (state._laserSfxStopTo) { clearTimeout(state._laserSfxStopTo); state._laserSfxStopTo = null; }
  const _ubeamR = document.getElementById('unibeam-sfx');
  if (_ubeamR) { _ubeamR.loop = false; _ubeamR.pause(); _ubeamR.currentTime = 0; }
  // Kill in-flight thunder rumble on title.
  if (typeof _thunderActiveSrc !== 'undefined' && _thunderActiveSrc) {
    try { _thunderActiveSrc.stop(); } catch (_) {}
    _thunderActiveSrc = null;
  }
  if (titleMusic) { titleMusic.currentTime = 0; setTrackVol('title', state.muted ? 0 : TRACK_VOL.title); if (!state.muted) titleMusic.play().catch(() => {}); }
  updateTitleCoins();
  updateTitleFuelCells();
  updateTitleLevel();
  updateTitleBadges();
  updateNotificationDots();
  updateStreakBadge();
  initSkinViewer();
  fetchLeaderboard();
}

// Clears all corridor flags — called by hotkeys so speed freeze doesn't carry over
// Wipes every in-flight gameplay object (cones, walls, lethal rings) and
// resets every mechanic flag so nothing lingers across repair-ship or restart.
function _clearAllMechanics() {
  // Return pooled objects
  for (let i = activeObstacles.length - 1; i >= 0; i--) returnObstacleToPool(activeObstacles[i]);
  activeObstacles.length = 0;
  [..._awActive].forEach(_returnWallToPool);
  _awActive.length = 0;
  for (const lr of _lethalRingActive) { lr.userData.active = false; lr.visible = false; lr.position.set(0,-9999,0); }
  _lethalRingActive.length = 0;
  // Reset all mechanic flags
  clearAllCorridorFlags();
  state.gauntletActive = false;
  state.gauntletRowsLeft = 0;
  state._arcActive = false;
  state._arcQueue = null;
  state._arcStage = 0;
}

function clearAllCorridorFlags() {
  state.corridorMode       = false;
  state.l4CorridorActive   = false;
  state.l4CorridorDone     = false;
  state.l5CorridorActive   = false;
  state.l5CorridorDone     = false;
  state.zipperActive       = false;
  state.slalomActive       = false;
  state.slalomRowsDone     = 0;
  state.slalomMaxRows      = 0;
  state.drPatternCooldown  = 0;
  state.drCustomPatternActive = false;
  state.drCustomPatternRow = 0;
  state.drCustomPatternSpawnZ = -7;
  state.angledWallsActive  = false;
  state.angledWallRowsDone = 0;
  state.angledWallSpawnZ   = -_awTuner.zSpacing;
  state._seqAngledTimer    = 0;
  state._seqStructuredTimer = 0;
  state._drL3MaxRows       = 0;
  state._drL4MaxRows       = 0;
  state._drL5MaxRows       = 0;
  state.corridorDelay      = 0;
  state.postL3Gap          = 0;
}

// Full state-wipe used by hotkey jumps. clearAllCorridorFlags() handles the
// active-flag set, but six categories of substate leak between hotkey jumps
// and corrupt the sequencer/visuals. This helper wipes them all.
function _drFullStateWipe() {
  // 1) Zipper substate
  state.zipperRowsLeft     = 0;
  state.zipperCooldown     = 0;
  state.zipperHoldCount    = 0;
  state.zipperRunCount     = 0;
  state.zipperSpawnTimer   = 0;
  // 2) Stage timers / one-shot fired flags
  state._seqZipTimer       = 0;
  state._seqZipFired       = false;
  state._seqSlalomFired    = false;
  state._seqStructuredTimer = 0;
  state._seqRampT01        = 0;
  state._seqAngledTimer    = 0;
  state._restBeepFired     = false;
  // S2 burst-rhythm state (cones_and_zips)
  state._seqZipBurstNum    = 0;
  state._seqZipRestTimer   = 0;
  // 3) Canyon flags — call stop helpers if currently active so they restore
  //    speed/FOV/lighting before we wipe their flags.
  if (state.l3KnifeCanyon && typeof _stopL3KnifeCanyon === 'function') _stopL3KnifeCanyon();
  if (state.preT4ACanyon  && typeof _stopPreT4ACanyon  === 'function') _stopPreT4ACanyon();
  if (state.preT4BCanyon  && typeof _stopPreT4BCanyon  === 'function') _stopPreT4BCanyon();
  state.preT4ACanyon       = false;
  state.preT4BCanyon       = false;
  // 4) L3 entry/done state — re-arm L3 knife on next entry
  state.l3KnifeDone        = false;
  state._l3EntryLogged     = false;
  // 5) Endless-mode rotation state (Shift+2 hotkey enters endless)
  state._endlessActiveType    = '';
  state._endlessBlockTimer    = 0;
  state._endlessRotationIdx   = 0;
  state._endlessCorridorCount = 0;
  // 6) Corridor sub-state (gap drift, row counter)
  state.corridorRowsDone   = 0;
  state.corridorGapCenter  = 0;
  state.corridorGapDir     = 1;
  state.corridorSpawnZ     = -7;
  // 7) L4 corridor center anchor — cleared so the next L4 activation captures
  //    a fresh ship X. _activeSunOverride is intentionally NOT cleared here:
  //    the running stage-entry vibe / override transitions already restore the
  //    correct sun on the next stage entry. Forcing it to null here would
  //    desync from the still-painted sun-shader uniforms when a hotkey jump
  //    lands on a stage that shares the same vibeIdx and has no override.
  state._l4CenterAnchor    = 0;
  state._l5CenterAnchor    = 0;
}

window.addEventListener('keydown', e => {
  keys[e.key] = true;
  const isSpace = (e.key === ' ' || e.code === 'Space');
  if (isSpace) e.preventDefault();
  // Snapshot phase BEFORE any action so we don't double-fire
  const phaseAtEvent = state.phase;
  const isMute = (e.key === 'm' || e.key === 'M');
  const isWaterToggle = (e.key === 'w' && !e.shiftKey);
  if (phaseAtEvent === 'title' && isWaterToggle) {
    mirrorMesh.visible = !mirrorMesh.visible;
    return;
  }
  const isEnter = (e.key === 'Enter');
  const isArrowLR = (e.key === 'ArrowLeft' || e.key === 'ArrowRight');
  // Arrow keys on title screen navigate skins (don't start game)
  if (phaseAtEvent === 'title' && isArrowLR) {
    if (e.key === 'ArrowLeft') { let _ni = (skinViewerIdx - 1 + SHIP_SKINS.length) % SHIP_SKINS.length; while (SHIP_SKINS[_ni] && SHIP_SKINS[_ni].hidden) _ni = (_ni - 1 + SHIP_SKINS.length) % SHIP_SKINS.length; navigateToSkin(_ni); }
    if (e.key === 'ArrowRight') { let _ni = (skinViewerIdx + 1) % SHIP_SKINS.length; while (SHIP_SKINS[_ni] && SHIP_SKINS[_ni].hidden) _ni = (_ni + 1) % SHIP_SKINS.length; navigateToSkin(_ni); }
    return;
  }
  if (isSpace && phaseAtEvent === 'title')   { playStartSound(); startGame(); }
  // if (isSpace && phaseAtEvent === 'playing') triggerJump(); // JUMP QUARANTINED
  if (e.key === 'Escape' && phaseAtEvent === 'playing') togglePause();
  if (e.key === 'Escape' && phaseAtEvent === 'paused')  togglePause();
  if (isSpace && phaseAtEvent === 'paused')  togglePause();
  if (isSpace && phaseAtEvent === 'dead')  { initAudio(); _triggerRetryWithSweep(); }
  // Enter skips the intro text sequence (with 250ms grace so a stray tap right after
  // pressing Play doesn't immediately kill the freshly-launched prologue)
  if (e.key === 'Enter' && state.phase === 'playing' && state.introActive && !state.isDeathRun &&
      (performance.now() - (state._introStartedAt || 0)) >= 250) {
    clearIntroTimers();
    const _ov = document.getElementById('intro-overlay');
    if (_ov) { fadeOutIntroOverlay(_ov); }
    state.introActive = false;
    beginThrusterSputter();
    // Trigger lift so ship rises from 0.38 to cruise height
    state._introLiftActive = true;
    state._introLiftTimer = 0;
    // engine-roar replaced with plasma-punch only (per user request 2026-04-27)
    playThrusterImpact(0.7);
    startEngineBaseline(0.5);
    state._argonSteering = false;
  }
  // Escape now pauses (handled above) — no longer returns to title
  // Hold-to-spin roll — up/down keys spin ship on Z axis while held
  if (state.phase === 'playing') {
    if (e.key === 'ArrowUp')   { state.rollHeld = true; state.rollDir = -1; }
    if (e.key === 'ArrowDown') { state.rollHeld = true; state.rollDir =  1; }
  }
  if (e.key === 'm' || e.key === 'M') toggleMute();
  // Level skipper for testing: press 1-5
  // ── Debug hotkeys: Sequencer stage jumping (numbers 1-9) + debug toggles ──
  const _digit = e.code.startsWith('Digit') ? e.code.replace('Digit','') : null;
  // ── JL mode: number keys jump to sequence sections ────────────────────────
  if (state._jetLightningMode && _digit) {
    // 1=0s  2=20s  3=30s(C1)  4=60s  5=75s  6=90s(C2)  7=123s  8=153s(C1+LT)  9=183s(C2+LT)  0=213s(peak)
    const _jlMap = { '1':0, '2':20, '3':30, '4':60, '5':75, '6':90, '7':123, '8':153, '9':183, '0':213 };
    if (_jlMap[_digit] !== undefined) {
      _jlJumpToTime(_jlMap[_digit]);
      return;
    }
  }
  if (state.phase === 'playing' && state.isDeathRun && _digit) {
    // Per-stage hotkeys, by NAME (survives DR_SEQUENCE reordering)
    // 1=S1_CONES  2=S2_CONES_ZIPS  3=S3_L3_CORRIDOR  4=S4_WALLS_RAND
    // 5=S5_WALLS_STRUCT  6=S6_RINGS  7=S7_L4_CORRIDOR  8=S8_FAT_CONES
    // 9=S9_SLALOM  0=S10_ZIPPER
    // Shift+1=S11_L5_CORRIDOR  Shift+2=ENDLESS
    // (Shift+3 retired — plain '3' now jumps to S3 which fires the knife canyon directly)
    const _digitNameMap = {
      '1': 'S1_CONES', '2': 'S2_CONES_ZIPS', '3': 'S3_L3_CORRIDOR',
      '4': 'S4_WALLS_RAND', '5': 'S5_WALLS_STRUCT', '6': 'S6_RINGS',
      '7': 'S7_L4_CORRIDOR', '8': 'S8_FAT_CONES', '9': 'S9_SLALOM',
      '0': 'S10_ZIPPER',
    };
    const _shiftDigitNameMap = {
      '1': 'S11_L5_CORRIDOR', '2': 'ENDLESS',
    };
    const _hotkeyJumpByName = (stageName) => {
      const idx = DR_SEQUENCE.findIndex(s => s.name === stageName);
      if (idx < 0) { console.warn('[SEQ-DEBUG] Stage not found: ' + stageName); return; }
      const s = DR_SEQUENCE[idx];
      clearAllCorridorFlags();
      _drFullStateWipe();
      state.deathRunRestBeat = 0;
      state.seqStageIdx = idx; state.seqStageElapsed = 0;
      state._seqCorridorStarted = false; state._seqSpawnMode = 'cones'; state._seqConeDensity = 'normal';
      state._seqVibeApplied = -1; state._restBeepFired = false;
      _setDRSpeed(BASE_SPEED * s.speed, 'KONAMI');
      // Fire music transition based on the most-recent musicTrack at or before this index
      let _t = null;
      for (let i = 0; i <= idx; i++) {
        if (DR_SEQUENCE[i].musicTrack) _t = DR_SEQUENCE[i].musicTrack;
      }
      if (_t) {
        const _fadeMs = (_t === 'l4') ? 2000 : 2000;
        musicFadeTo(_t, _fadeMs);
      }
    };
    if (e.shiftKey && _shiftDigitNameMap[_digit]) {
      if (_shiftDigitNameMap[_digit] === 'ENDLESS') {
        state.drPhase = 'RELEASE'; state.drPhaseTimer = 0; state.drPhaseDuration = 2;
      }
      _hotkeyJumpByName(_shiftDigitNameMap[_digit]);
    } else if (!e.shiftKey && _digitNameMap[_digit]) {
      _hotkeyJumpByName(_digitNameMap[_digit]);
    }
    return; // consume key in DR mode
  }
  // toggle no-spawn test mode
  if ((e.key === "'" || e.key === '`' || e.key === '\\' || e.key === 'n' || e.key === 'N') && state.phase === 'playing') {
    _noSpawnMode = !_noSpawnMode;
    // Flash HUD message so player knows it fired
    const _nsEl = document.createElement('div');
    _nsEl.textContent = _noSpawnMode ? 'SPAWN OFF' : 'SPAWN ON';
    _nsEl.style.cssText = 'position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);color:#fff;font-family:monospace;font-size:24px;font-weight:bold;pointer-events:none;z-index:9999;opacity:1;transition:opacity 1s';
    document.body.appendChild(_nsEl);
    setTimeout(() => { _nsEl.style.opacity = '0'; setTimeout(() => _nsEl.remove(), 1000); }, 500);
  }

  // In-game powerup hotkeys (playing only, >1s in): L=laser S=shield I=invincible M=magnet
  if (state.phase === 'playing' && (state.elapsed || 0) > 1.0) {
    if (e.key === 'l' || e.key === 'L') applyPowerup(1); // laser
    if (e.key === 's' || e.key === 'S') applyPowerup(0); // shield
    if (e.key === 'i' || e.key === 'I') applyPowerup(2); // invincible
    if (e.key === 'm' || e.key === 'M') applyPowerup(3); // magnet

    // Z/X/C/V — SPAWN a cube in front of the ship (so you can fly into it & test shatter).
    // Shield=Z, Laser=X, Overdrive=C, Magnet=V. 30u ahead of ship at lane center.
    const _spawnCubeAhead = (idx) => {
      if (typeof getPooledPowerup !== 'function' || typeof activePowerups === 'undefined') return;
      const pu = getPooledPowerup(idx);
      if (!pu) return;
      const z = (typeof shipGroup !== 'undefined' && shipGroup) ? shipGroup.position.z - 30 : -30;
      pu.position.set(state.shipX || 0, 1.5, z);
      activePowerups.push(pu);
    };
    if (e.key === 'z' || e.key === 'Z') _spawnCubeAhead(0); // shield cube
    if (e.key === 'x' || e.key === 'X') _spawnCubeAhead(1); // laser cube
    if (e.key === 'c' || e.key === 'C') _spawnCubeAhead(2); // overdrive cube
    if (e.key === 'v' || e.key === 'V') _spawnCubeAhead(3); // magnet cube
  }

  // T = toggle skin tuner (HOLO POWERUPS sliders live here). Works any phase, no admin gate.
  if ((e.key === 't' || e.key === 'T') && !e.ctrlKey && !e.metaKey && !e.altKey) {
    const tag = (e.target && e.target.tagName) || '';
    if (tag === 'INPUT' || tag === 'TEXTAREA') return; // don't hijack typing
    if (typeof window.toggleSkinTuner === 'function') {
      window.toggleSkinTuner();
      e.preventDefault();
    }
  }

  // R = spawn bonus rings + tuner (DR only)
  if ((e.key === 'r' || e.key === 'R') && !state._tutorialActive) {
    if (state.isDeathRun && state.phase === 'playing') {
      if (_bonusRings.length === 0) {
        _ringSpawnRow();
        _setDRSpeed(0, 'RING_PAUSE'); // live pause for tuning
      } else {
        _setDRSpeed(BASE_SPEED * (LEVELS[Math.min((state.deathRunSpeedTier || 0) + 1, 4)].speedMult), 'RING_PAUSE');
      }
      _ringShowTuner();
    }
  }
  // P = force custom pattern (DR only)
  if (e.key === 'p' || e.key === 'P') {
    if (state.isDeathRun && state.phase === 'playing') {
      state.drPhase = 'RELEASE'; state.drPhaseTimer = 0; state.drPhaseDuration = 2;
      const _s = DR_SEQUENCE[13]; if (_s) {
        clearAllCorridorFlags(); state.deathRunRestBeat = 0;
        state.seqStageIdx = 13; state.seqStageElapsed = 0;
        state._seqCorridorStarted = false; state._seqSpawnMode = 'cones'; state._seqConeDensity = 'normal';
        state._seqVibeApplied = -1;
        _setDRSpeed(BASE_SPEED * _s.speed, 'KONAMI');
      }
    }
  }
  // ── Force specific mechanics / arcs (DR only) ──
  if (state.isDeathRun && state.phase === 'playing') {
    let _forceBandIdx = DR2_RUN_BANDS.length - 1;
    for (let bi = 0; bi < DR2_RUN_BANDS.length; bi++) {
      if (state.elapsed < DR2_RUN_BANDS[bi].maxTime) { _forceBandIdx = bi; break; }
    }
    const _forceBand = DR2_RUN_BANDS[_forceBandIdx];
    const _forceKey = e.key.toUpperCase();
    const _forceMap = {
      'C': 'CORRIDOR_ARC',
      'X': 'SLALOM_ARC',
      'Z': 'ZIPPER_ARC',
      'V': 'L3_CORRIDOR',
      'K': 'L4_SINE_CORRIDOR',
      'J': 'L5_SINE_CORRIDOR',
      // 'Q' reserved for GOD MODE panel toggle (see 72-main-late-mid.js)
      'N': 'ZIPPER',
      'B': 'ANGLED_WALL',
    };
    if (_forceMap[_forceKey]) {
      const famKey = _forceMap[_forceKey];
      const fam = DR_MECHANIC_FAMILIES[famKey];
      if (fam) {
        clearAllCorridorFlags(); state.deathRunRestBeat = 0;
        state.drPhase = 'BUILD'; state.drPhaseTimer = 0; state.drPhaseDuration = 0;
        fam.activate(_forceBand, 'build');
      }
    }
  }
  // Campaign mode: original level-skip keys
  if (state.phase === 'playing' && !state.isDeathRun && ['1','2','3','4','5'].includes(e.key)) {
    const idx = parseInt(e.key) - 1;
    if (idx < LEVELS.length) {
      clearAllCorridorFlags();
      state.currentLevelIdx = idx;
      state.score = LEVELS[idx].scoreThreshold;
      currentLevelDef = LEVELS[idx];
      targetLevelDef  = LEVELS[idx];
      transitionT     = 1;
      applyLevelVisuals(LEVELS[idx]);
      updateHUDLevel();
      if (idx <= 1) setActiveMusic('bg');
      else if (idx === 2) setActiveMusic('l3');
      else if (idx >= 3) setActiveMusic('l4');
    }
  }
  // Key 0: toggle debug hitbox wireframes (campaign)
  if (state.phase === 'playing' && !state.isDeathRun && e.key === '0') {
    debugHitboxes = !debugHitboxes;
  }
  // Key T: toggle L4 aurora tendrils
  // Campaign key 9: skip to right before L4 corridor
  if (state.phase === 'playing' && !state.isDeathRun && e.key === '9') {
    clearAllCorridorFlags();
    const l4 = LEVELS[3];
    state.currentLevelIdx  = 3;
    state.score            = l4.scoreThreshold;
    currentLevelDef = l4; targetLevelDef = l4; transitionT = 1;
    applyLevelVisuals(l4); updateHUDLevel();
    state.levelElapsed     = L4_CORRIDOR_TRIGGER_S - 2;
    state.l4CorridorActive = false;
    state.l4CorridorDone   = false;
    state.l4RowsDone       = 0;
    state.l4SineT          = 0;
    setActiveMusic('l4');
  }
  // Campaign key 7: skip to midway through L3 corridor
  if (state.phase === 'playing' && !state.isDeathRun && e.key === '7') {
    const l3 = LEVELS[2];
    state.currentLevelIdx = 2;
    state.score           = l3.scoreThreshold + 171;
    currentLevelDef = l3; targetLevelDef = l3; transitionT = 1;
    applyLevelVisuals(l3); updateHUDLevel();
    state.corridorMode       = true;
    state.corridorSpawnZ     = -7;
    state.corridorRowsDone   = 200;
    state.corridorDelay      = 0;
    state.corridorGapCenter  = 0;
    state.corridorGapDir     = 1;
    state.corridorSineT      = 0;
    state.levelElapsed       = 68;
    state.postL3Gap          = 0;
    setActiveMusic('l3');
  }
  // Campaign key 6: skip to L5 post-2nd-zipper
  if (state.phase === 'playing' && !state.isDeathRun && e.key === '6') {
    clearAllCorridorFlags();
    const l5 = LEVELS[4];
    state.currentLevelIdx = 4;
    state.score = l5.scoreThreshold;
    currentLevelDef = l5; targetLevelDef = l5; transitionT = 1;
    applyLevelVisuals(l5); updateHUDLevel();
    // Fast-forward zipper state to: 2 runs done, random cones phase starting
    state.zipperActive        = false;
    state.zipperRunCount      = 2;
    l5DustPoints.visible = true;  // key-6 skip: enable chromatic dust
    // l4 is the correct track here — title fires when corridor ends
    setActiveMusic('l4');
    state.zipperCooldown      = 99999;
    state.l5EndingActive      = false;
    state.l5CorridorActive    = false;
    state.l5CorridorDone      = false;
    state.l5CorridorRowsDone  = 0;
    state.l5CorridorSpawnZ    = -7;
    state.l5SineT             = 0;
    state.l5RandomAfterZipper = 5.0;  // 5s of random cones, then corridor fires

  }
});
window.addEventListener('keyup', e => {
  keys[e.key] = false;
  // Release thrust on spacebar up
  // if (e.key === ' ') _thrustHeld = false; // JUMP QUARANTINED
  // Release roll spin
  if (e.key === 'ArrowUp' || e.key === 'ArrowDown') {
    state.rollHeld = false;
    // Keep rollDir so we know which way to return
  }
});

// ── TOUCH CONTROLS ──────────────────────────────────────────────────────────
(function setupTouch() {
  // Swipe threshold in pixels — swipe up/down to toggle roll
  const SWIPE_THRESH = 14;

  function bindSteerZone(id, stateKey, rollKey) {
    const el = document.getElementById(id);
    if (!el) return;

    // Per-touch tracking: touchId -> { startY, swiped }
    const activeTouches = new Map();

    const setSteer = (v) => {
      touch[stateKey] = v;
      if (v) el.classList.add('active');
      else   el.classList.remove('active');
    };

    el.addEventListener('touchstart', e => {
      e.preventDefault();
      // If intro is active — tap anywhere skips it (250ms grace so the follow-through
      // tap from "tap to play" doesn't immediately kill the freshly-launched prologue)
      if (state.phase === 'playing' && state.introActive && !state.isDeathRun &&
          (performance.now() - (state._introStartedAt || 0)) >= 250) {
        const _ov = document.getElementById('intro-overlay');
        clearIntroTimers();
        if (_ov) fadeOutIntroOverlay(_ov);
        state.introActive = false;
        beginThrusterSputter();
        state._introLiftActive = true;
        state._introLiftTimer = 0;
        // engine-roar replaced with plasma-punch only (per user request 2026-04-27)
        playThrusterImpact(0.7);
        startEngineBaseline(0.5);
        state._argonSteering = false;
        return;
      }
      // Start game if on title/dead — mark this touch as game-starting (ignore swipes from it)
      const ph = state.phase;
      const isStartingTouch = (ph === 'title' || ph === 'dead');
      for (const t of e.changedTouches) {
        activeTouches.set(t.identifier, { startY: t.clientY, swiped: false, isStart: isStartingTouch });
      }
      // Enable steering while finger is down
      setSteer(true);
      if (isStartingTouch) {
        if (ph === 'dead') {
          if (!_gameOverTapReady) return; // cooldown guard
          _triggerRetryWithSweep();
        }
        else if (ph === 'title') startGame();
      }
    }, { passive: false });

    el.addEventListener('touchmove', e => {
      e.preventDefault();
      // Only allow roll toggle during active gameplay (not title, death, intro)
      if (state.phase === 'playing' && !state.introActive) {
        for (const t of e.changedTouches) {
          const info = activeTouches.get(t.identifier);
          if (!info || info.swiped || info.isStart) continue;
          const dy = t.clientY - info.startY;
          if (dy < -SWIPE_THRESH) {
            info.swiped = true;
            touch.rollToggle = true;
            touch.rollUp = true;
            touch.rollDown = false;
          } else if (dy > SWIPE_THRESH) {
            info.swiped = true;
            touch.rollToggle = false;
            touch.rollUp = false;
            touch.rollDown = false;
          }
        }
      }
    }, { passive: false });

    const endTouch = (e) => {
      e.preventDefault();
      // Catch quick flicks that touchmove missed
      if (state.phase === 'playing' && !state.introActive) {
        for (const t of e.changedTouches) {
          const info = activeTouches.get(t.identifier);
          if (!info || info.swiped || info.isStart) continue;
          const dy = t.clientY - info.startY;
          if (dy < -SWIPE_THRESH) {
            touch.rollToggle = true;
            touch.rollUp = true;
            touch.rollDown = false;
          } else if (dy > SWIPE_THRESH) {
            touch.rollToggle = false;
            touch.rollUp = false;
            touch.rollDown = false;
          }
        }
      }
      for (const t of e.changedTouches) {
        activeTouches.delete(t.identifier);
      }
      // Release steer when no touches remain in this zone
      // Roll toggle persists — does NOT release on finger lift
      if (activeTouches.size === 0) {
        setSteer(false);
      }
    };
    el.addEventListener('touchend',    endTouch, { passive: false });
    el.addEventListener('touchcancel', endTouch, { passive: false });
  }

  // Left zone: steer left, swipe-up = rollUp (dir -1)
  // Right zone: steer right, swipe-up = rollDown (dir +1)
  bindSteerZone('touch-left',  'left',  'rollUp');
  bindSteerZone('touch-right', 'right', 'rollDown');

  const pauseBtn = document.getElementById('touch-pause');
  if (pauseBtn) {
    pauseBtn.addEventListener('touchstart', e => {
      e.preventDefault();
      togglePause();
    }, { passive: false });
  }

  // Triple-tap skin label = unlock entire shop (all skins + all powerups max tier)
  const skinLabel = document.getElementById('skin-viewer-label');
  let _skinTapCount = 0;
  let _skinTapTimer = null;
  function _adminUnlockAll() {
    // Unlock all skins
    const allSkinNames = SHIP_SKINS.map(s => s.name);
    window._LS.setItem('jh_owned_skins', JSON.stringify(allSkinNames));
    // Unlock all powerups
    const allPuIds = POWERUP_TYPES.map(p => p.id);
    window._LS.setItem('jetslide_pu_unlocked', JSON.stringify(allPuIds));
    // Give plenty of fuel to buy upgrades
    saveFuelCells(loadFuelCells() + 99999);
    updateTitleFuelCells();
  }
  if (skinLabel) {
    skinLabel.addEventListener('touchstart', e => {
      _skinTapCount++;
      if (_skinTapTimer) clearTimeout(_skinTapTimer);
      if (_skinTapCount >= 3) { _skinTapCount = 0; _adminUnlockAll(); return; }
      _skinTapTimer = setTimeout(() => { _skinTapCount = 0; }, 500);
    }, { passive: true });
    _tapBind(skinLabel, () => {
      _skinTapCount++;
      if (_skinTapTimer) clearTimeout(_skinTapTimer);
      if (_skinTapCount >= 3) { _skinTapCount = 0; _adminUnlockAll(); return; }
      _skinTapTimer = setTimeout(() => { _skinTapCount = 0; }, 500);
    });
  }
})();

